          updated: "Updated recently",
        },
        { name: "337010601-सडक डिभिजन, धनकुटा", updated: "Updated recently" },
        { name: "337011001-सडक डिभिजन, हर्कपुर", updated: "Updated recently" },
        {
          name: "337011101-गाइघाट दिक्तेल सडक योजना, गाइघाट",
          updated: "Updated recently",
        },
        {
          name: "337011103-मिर्चैया-कटारी-घुर्मि सडक योजना, कटारी",
          updated: "Updated recently",
        },
        { name: "337011201-सडक डिभिजन, दमक", updated: "Updated recently" },
        {
          name: "337011203-मदन भण्डारी राजमार्ग योजना कार्यालय, दमक",
