  const fetchData = useCallback(() => {
    if (accessToken) {
      setLoading(true);
      triggerHaptic("medium");
      fetchSpreadsheetMeta(
        "1ohBXufi7WEvKVAdMavbM5ZQfWnjxveFxgR0FJZf4EJM",
        accessToken,
      )
        .then((meta) => {
          const sheet0 =
            meta.sheets?.find(
              (s: any) => String(s.properties.sheetId) === "0",
            ) || meta.sheets?.[0];

          const sheetOffices = meta.sheets?.find(
            (s: any) => String(s.properties.sheetId) === "40941786",
          );

          const title0 = sheet0
            ? sheet0.properties.title
            : "सडक बिभाग प्रगति Dashboard";
          const titleOffices = sheetOffices
            ? sheetOffices.properties.title
            : "To be updated Every Week_Cumulative";

          return Promise.all([
            fetchSheetData(
              "1ohBXufi7WEvKVAdMavbM5ZQfWnjxveFxgR0FJZf4EJM",
              `${title0}!A1:Z250`,
              accessToken,
            ),
            fetchSheetData(
              "1ohBXufi7WEvKVAdMavbM5ZQfWnjxveFxgR0FJZf4EJM",
              `${titleOffices}!A1:Z250`,
              accessToken,
            ),
          ]);
        })
        .then(([data0, dataOffices]) => {
          // 1. Process data0 (Indicators & Metadata)
          if (data0.values) {
            const csvText0 = data0.values
              .map((row: any[]) =>
                row
                  .map((val) => {
                    const str = String(
                      val === undefined || val === null ? "" : val,
                    );
                    return `"${str.replace(/"/g, '""')}"`;
                  })
                  .join(","),
              )
              .join("\n");

            const { indicators: parsedList, metadata: parsedMeta } =
              parseGoogleSheetsCSV(csvText0);

            if (parsedList && parsedList.length > 0) {
              setIndicators(parsedList);
              setMetadata(parsedMeta);

              try {
                localStorage.setItem(
                  "dor_indicators_cache",
                  JSON.stringify(parsedList),
                );
                localStorage.setItem(
                  "dor_metadata_cache",
                  JSON.stringify(parsedMeta),
                );
              } catch (e) {
                // Suppress redundant log
              }
            }
          }

          // 2. Process dataOffices (Offices)
          if (dataOffices.values) {
            const rows = dataOffices.values;

            let officeColIdx = 1; // Default column index is 1 for Office column
            let headerRowIdx = -1;

            // Look for a row containing the "Office" header dynamically
            for (let i = 0; i < rows.length; i++) {
              const row = rows[i];
              if (
                row &&
                row.some((val: any) => {
                  const s = String(val).toLowerCase();
                  return s.includes("office") || s.includes("कार्यालय");
                })
              ) {
                headerRowIdx = i;
                officeColIdx = row.findIndex((val: any) => {
                  const s = String(val).toLowerCase();
                  return s.includes("office") || s.includes("कार्यालय");
                });
                if (officeColIdx === -1) officeColIdx = 1;
                break;
              }
            }

            const parsedOffices: { name: string; updated: string }[] = [];
            const startRowIdx = headerRowIdx !== -1 ? headerRowIdx + 1 : 0;

            for (let i = startRowIdx; i < rows.length; i++) {
              const row = rows[i];
              if (!row || row.length <= officeColIdx) continue;
              const officeName = String(row[officeColIdx] || "").trim();
              if (
                officeName &&
                officeName !== "Total" &&
                officeName !== "कुल" &&
                !officeName.toLowerCase().includes("note:") &&
                !officeName.includes("To be updated") &&
                !officeName.startsWith("=") &&
                officeName.length > 3
              ) {
                parsedOffices.push({
                  name: officeName,
                  updated: "Updated recently",
                });
              }
            }

            if (parsedOffices.length > 0) {
              setOffices(parsedOffices);
              try {
                localStorage.setItem(
                  "dor_offices_cache",
                  JSON.stringify(parsedOffices),
                );
              } catch (e) {
                // Suppress redundant log
              }
            }
          }

          setLoading(false);
          setPulseKey((prev) => prev + 1);
        })
        .catch((err) => {
          console.error("Error fetching/parsing Google Sheets:", err);
          setLoading(false);
        });
    }
  }, [accessToken]);

