                    voiceSuccessTrigger 
                      ? "bg-emerald-500/10 border-emerald-500/20 text-emerald-400" 
                      : "bg-indigo-500/10 border-indigo-500/20 text-indigo-400"
                  }`}>
                    {voiceFeedback}
                  </p>
                ) : (
                  <div className="bg-slate-800/50 dark:bg-slate-900/50 p-3.5 rounded-xl border border-slate-800/30">
                    <p className="text-[10px] text-slate-400 font-bold uppercase tracking-wider mb-1.5">
                      {language === "en" ? "Try saying:" : "यसरी भन्नुहोस्:"}
                    </p>
                    <ul className="text-xs text-indigo-200 space-y-1 font-medium list-disc pl-3">
                      <li>"Go to Chart View"</li>
                      <li>"Show Table View"</li>
                      <li>"Go to Heatmap"</li>
                      <li>"Go to Dashboard"</li>
                    </ul>
                  </div>
                )}
              </div>
            </motion.div>
          )}
        </AnimatePresence>

        <PWAInstallBanner />
      </div>
    </>
  );
}

export default function App() {
  const [isReady, setIsReady] = useState(() => {
    if (typeof window !== "undefined") {
      try {
        return localStorage.getItem("dor_app_ready") === "true";
      } catch (e) {
        return false;
      }
    }
    return false;
  });

  useEffect(() => {
    if (isReady) {
      localStorage.setItem("dor_app_ready", "true");
    }
  }, [isReady]);

  return (
    <LanguageProvider>
      <TextScaleProvider>
        <AuthProvider>
          {!isReady ? (
            <StartupScreen onComplete={() => setIsReady(true)} />
          ) : (
            <MainAppContent />
          )}
        </AuthProvider>
      </TextScaleProvider>
    </LanguageProvider>
  );
}

