import React, { useState, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'motion/react';
import { X, Mic, MicOff, Send, Sparkles, Loader2, Volume2 } from 'lucide-react';
import { useLanguage } from '../context/LanguageContext';

interface AIAssistantModalProps {
  isOpen: boolean;
  onClose: () => void;
}

// Ensure TypeScript knows about window.SpeechRecognition and window.webkitSpeechRecognition
declare global {
  interface Window {
    SpeechRecognition: any;
    webkitSpeechRecognition: any;
  }
}

export function AIAssistantModal({ isOpen, onClose }: AIAssistantModalProps) {
  const { language, t } = useLanguage();
  const [isListening, setIsListening] = useState(false);
  const [transcript, setTranscript] = useState('');
  const [messages, setMessages] = useState<{role: 'user'|'assistant', content: string}[]>([
    { role: 'assistant', content: language === 'en' ? 'Hello! I am your AI assistant. You can ask me questions about Indicator status.' : 'नमस्ते! म तपाईंको एआई सहायक हुँ। तपाईं मलाई सूचक स्थितिको बारेमा प्रश्न सोध्न सक्नुहुन्छ।' }
  ]);
  const [isProcessing, setIsProcessing] = useState(false);

  const recognitionRef = useRef<any>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (messagesEndRef.current) {
      messagesEndRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [messages]);

  useEffect(() => {
    if (!isOpen) {
      if (isListening && recognitionRef.current) {
        recognitionRef.current.stop();
        setIsListening(false);
      }
      return;
    }

    // Initialize speech recognition
    if ('SpeechRecognition' in window || 'webkitSpeechRecognition' in window) {
      const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
      recognitionRef.current = new SpeechRecognition();
      recognitionRef.current.continuous = false;
      recognitionRef.current.interimResults = true;
      recognitionRef.current.lang = language === 'en' ? 'en-US' : 'ne-NP';

      recognitionRef.current.onstart = () => {
        setIsListening(true);
      };

      recognitionRef.current.onresult = (event: any) => {
        let interimTranscript = '';
        let finalTranscript = '';

        for (let i = event.resultIndex; i < event.results.length; ++i) {
          if (event.results[i].isFinal) {
            finalTranscript += event.results[i][0].transcript;
          } else {
            interimTranscript += event.results[i][0].transcript;
          }
        }

        if (finalTranscript) {
          setTranscript(finalTranscript);
          handleSendMessage(finalTranscript);
        } else {
          setTranscript(interimTranscript);
        }
      };

      recognitionRef.current.onerror = (event: any) => {
        console.error('Speech recognition error', event.error);
        setIsListening(false);

        if (event.error === 'not-allowed') {
          setMessages(prev => [...prev, { 
            role: 'assistant', 
            content: language === 'en' 
              ? 'Microphone access denied. Please ensure you have allowed microphone permissions in your browser and that the page is served over HTTPS.' 
              : 'माइक पहुँच अस्वीकार गरियो। कृपया तपाईंको ब्राउजरमा माइक अनुमतिहरू दिनुभएको सुनिश्चित गर्नुहोस् र पृष्ठ HTTPS मार्फत उपलब्ध भएको सुनिश्चित गर्नुहोस्।' 
          }]);
        } else if (event.error === 'no-speech') {
          // Don't necessarily add a message for no-speech, just stop listening
        } else {
          setMessages(prev => [...prev, { 
            role: 'assistant', 
            content: language === 'en' 
              ? `Speech recognition error: ${event.error}` 
              : `आवाज पहिचान त्रुटि: ${event.error}` 
          }]);
        }
      };

      recognitionRef.current.onend = () => {
        setIsListening(false);
      };
    } else {
      console.warn('Speech recognition not supported in this browser.');
    }

    return () => {
      if (recognitionRef.current && isListening) {
        recognitionRef.current.stop();
      }
    };
  }, [isOpen, language]);

  const toggleListening = () => {
    if (isListening) {
      recognitionRef.current?.stop();
    } else {
      setTranscript('');
      recognitionRef.current?.start();
    }
  };

  const handleSendMessage = async (text: string) => {
    if (!text.trim()) return;

    const newMessages = [...messages, { role: 'user' as const, content: text }];
    setMessages(newMessages);
    setTranscript('');
    setIsProcessing(true);

    try {
      // Map messages for the history format expected by the API
      const history = messages.slice(1).map(msg => ({
        role: msg.role === 'assistant' ? 'model' : 'user',
        parts: [{ text: msg.content }]
      }));

      const response = await fetch('/api/ai/chat', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ message: text, history })
      });

      if (!response.ok) {
        throw new Error('Network response was not ok');
      }

      const data = await response.json();

      let assistantReply = data.text;
      const functionCalls = data.functionCalls || [];

      // Process function calls
      if (functionCalls.length > 0) {
        for (const call of functionCalls) {
          switch (call.name) {
            case 'open_page':
              window.dispatchEvent(new CustomEvent('ai:open_page', { detail: call.args }));
              assistantReply += `\nOpening ${call.args.page} view...`;
              break;
            case 'make_report':
              window.dispatchEvent(new CustomEvent('ai:make_report', { detail: call.args }));
              assistantReply += `\nGenerating ${call.args.type} report...`;
              break;
            case 'print_screen':
              window.dispatchEvent(new CustomEvent('ai:print_screen'));
              assistantReply += '\nOpening print dialog...';
              break;
            case 'show_menu':
              window.dispatchEvent(new CustomEvent('ai:show_menu'));
              assistantReply += '\nShowing menu options...';
              break;
            case 'set_volume':
              window.dispatchEvent(new CustomEvent('ai:set_volume', { detail: call.args }));
              assistantReply += `\nVolume ${call.args.enabled ? 'enabled' : 'disabled'}.`;
              break;
          }
        }
      }

      if (!assistantReply) {
        assistantReply = language === 'en' ? 'Done.' : 'भयो।';
      }

      setMessages([...newMessages, { 
        role: 'assistant', 
        content: assistantReply
      }]);
    } catch (error) {
      console.error('AI processing error:', error);
      setMessages([...newMessages, { 
        role: 'assistant', 
        content: language === 'en' 
          ? 'Sorry, I encountered an error communicating with the server.' 
          : 'माफ गर्नुहोस्, सर्भरसँग सञ्चार गर्दा मैले एउटा त्रुटि सामना गरें।' 
      }]);
    } finally {
      setIsProcessing(false);
    }
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[5000] flex items-center justify-center p-4 sm:p-6 bg-slate-900/40 backdrop-blur-sm">
      <motion.div
        initial={{ opacity: 0, scale: 0.95, y: 20 }}
        animate={{ opacity: 1, scale: 1, y: 0 }}
        exit={{ opacity: 0, scale: 0.95, y: 20 }}
        className="w-full max-w-lg bg-white dark:bg-slate-900 rounded-3xl shadow-2xl overflow-hidden border border-slate-200 dark:border-slate-800 flex flex-col h-[600px] max-h-[85vh]"
      >
        {/* Header */}
        <div className="flex items-center justify-between px-6 py-4 border-b border-slate-100 dark:border-slate-800 bg-indigo-600 dark:bg-indigo-900 text-white shrink-0">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-full bg-white/20 flex items-center justify-center">
              <Sparkles size={20} />
            </div>
            <div>
              <h2 className="text-sm font-bold">{language === 'en' ? 'AI Assistant' : 'एआई सहायक'}</h2>
              <p className="text-[0.625rem] text-indigo-100 uppercase tracking-wider">{language === 'en' ? 'Voice Enabled' : 'भ्वाइस सक्षम'}</p>
            </div>
          </div>
          <button
            onClick={onClose}
            className="w-8 h-8 rounded-full hover:bg-white/10 flex items-center justify-center transition-colors"
          >
            <X size={18} />
          </button>
        </div>

        {/* Chat Area */}
        <div className="flex-1 overflow-y-auto p-4 sm:p-6 space-y-4 bg-slate-50/50 dark:bg-slate-950/50 custom-scroll">
          {messages.map((msg, idx) => (
            <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
              <div className={`max-w-[80%] rounded-2xl p-4 shadow-sm ${
                msg.role === 'user' 
                  ? 'bg-indigo-600 text-white rounded-br-sm' 
                  : 'bg-white dark:bg-slate-800 text-slate-700 dark:text-slate-300 border border-slate-100 dark:border-slate-700 rounded-bl-sm'
              }`}>
                <p className="text-sm">{msg.content}</p>
              </div>
            </div>
          ))}

          {isProcessing && (
            <div className="flex justify-start">
              <div className="bg-white dark:bg-slate-800 border border-slate-100 dark:border-slate-700 rounded-2xl rounded-bl-sm p-4 shadow-sm flex items-center gap-2">
                <Loader2 size={16} className="text-indigo-600 animate-spin" />
                <span className="text-xs text-slate-500">{language === 'en' ? 'Thinking...' : 'सोच्दै हुनुहुन्छ...'}</span>
              </div>
            </div>
          )}
          <div ref={messagesEndRef} />
        </div>

        {/* Input Area */}
        <div className="p-4 sm:p-6 border-t border-slate-100 dark:border-slate-800 bg-white dark:bg-slate-900 shrink-0">

          {/* Transcript Preview */}
          <AnimatePresence>
            {transcript && (
              <motion.div 
                initial={{ opacity: 0, height: 0 }}
                animate={{ opacity: 1, height: 'auto' }}
                exit={{ opacity: 0, height: 0 }}
                className="mb-4 p-3 bg-indigo-50 dark:bg-indigo-900/20 rounded-xl text-xs text-indigo-700 dark:text-indigo-300 italic flex items-center gap-2 border border-indigo-100 dark:border-indigo-800/50"
              >
                <Volume2 size={14} className="animate-pulse shrink-0" />
                <span className="line-clamp-2">{transcript}</span>
              </motion.div>
            )}
          </AnimatePresence>

          <div className="flex items-end gap-3">
            <div className="flex-1 relative">
              <input
                type="text"
                placeholder={isListening 
                  ? (language === 'en' ? 'Listening...' : 'सुन्दैछ...') 
                  : (language === 'en' ? 'Ask a question or use voice...' : 'प्रश्न सोध्नुहोस् वा भ्वाइस प्रयोग गर्नुहोस्...')
                }
                value={transcript}
                onChange={(e) => setTranscript(e.target.value)}
                onKeyDown={(e) => {
                  if (e.key === 'Enter') handleSendMessage(transcript);
                }}
                className={`w-full px-4 py-3.5 text-sm rounded-2xl border bg-slate-50 dark:bg-slate-900 outline-none transition-colors ${
                  isListening 
                    ? 'border-indigo-400 bg-indigo-50/30 text-indigo-800 dark:text-indigo-200 shadow-[0_0_0_4px_rgba(79,70,229,0.1)]' 
                    : 'border-slate-200 dark:border-slate-700 text-slate-700 dark:text-slate-300 focus:border-indigo-500 focus:ring-4 focus:ring-indigo-500/10'
                }`}
              />
            </div>

            <button
              onClick={toggleListening}
              className={`w-12 h-12 rounded-2xl flex items-center justify-center transition-all shrink-0 shadow-sm ${
                isListening
                  ? 'bg-red-50 text-red-600 border border-red-200 hover:bg-red-100 animate-pulse'
                  : 'bg-white dark:bg-slate-800 text-slate-500 border border-slate-200 dark:border-slate-700 hover:text-indigo-600 hover:border-indigo-300'
              }`}
              title={language === 'en' ? 'Voice Input' : 'भ्वाइस इनपुट'}
            >
              {isListening ? <MicOff size={20} /> : <Mic size={20} />}
            </button>

            <button
              onClick={() => handleSendMessage(transcript)}
              disabled={!transcript.trim()}
              className={`w-12 h-12 rounded-2xl flex items-center justify-center transition-all shrink-0 shadow-sm ${
                transcript.trim()
                  ? 'bg-indigo-600 text-white hover:bg-indigo-700 hover:-translate-y-0.5'
                  : 'bg-slate-100 dark:bg-slate-800 text-slate-400 cursor-not-allowed border border-slate-200 dark:border-slate-700'
              }`}
            >
              <Send size={18} className={transcript.trim() ? 'ml-1' : ''} />
            </button>
          </div>
        </div>
      </motion.div>
    </div>
  );
}

import React, { useMemo } from 'react';
import { motion, AnimatePresence } from 'motion/react';
import { 
  X, Clock, User, ArrowRight, TrendingUp, HelpCircle, 
  CheckCircle, Database, Calendar, Weight, FileSpreadsheet, 
  ShieldAlert, Sparkles, RefreshCw, BarChart2
} from 'lucide-react';
import { useLanguage } from '../context/LanguageContext';
import { Indicator } from '../types';

interface ActivityDetailDrawerProps {
  isOpen: boolean;
  onClose: () => void;
  entry: any | null; // Selected update log entry from updates_history
  updatesHistory: any[];
}

export const ActivityDetailDrawer: React.FC<ActivityDetailDrawerProps> = ({
  isOpen,
  onClose,
  entry,
  updatesHistory = []
}) => {
  const { language, t } = useLanguage();

  // Find the 'Before' snapshot preceding the current entry in chronological order
  const comparisonData = useMemo(() => {
    if (!entry) return null;

    // Sort chronologically to find the true preceding snapshot
    const sortedHistory = [...updatesHistory].sort((a, b) => {
      const aTime = new Date(a.createdAt || a.id).getTime();
      const bTime = new Date(b.createdAt || b.id).getTime();
      return aTime - bTime;
    });

    const currentIdx = sortedHistory.findIndex(h => h.id === entry.id);
    const beforeEntry = currentIdx > 0 ? sortedHistory[currentIdx - 1] : null;

    const afterIndicators = entry.indicators || [];
    const beforeIndicators = beforeEntry?.indicators || [];

    const changes = afterIndicators.map((afterInd: any) => {
      const beforeInd = beforeIndicators.find((b: any) => b.id === afterInd.id || b.name === afterInd.name);

      const beforeVal = beforeInd ? beforeInd.annualProgress : 0;
      const afterVal = afterInd.annualProgress;
      const target = afterInd.annualTarget || 100;

      const beforePct = target > 0 ? Math.min(100, Math.round((beforeVal / target) * 100)) : 0;
      const afterPct = target > 0 ? Math.min(100, Math.round((afterVal / target) * 100)) : 0;

      const diffProgress = afterVal - beforeVal;
      const diffPct = afterPct - beforePct;

      // Status badges
      const getStatusType = (pct: number) => {
        if (pct >= 80) return { label: language === 'en' ? 'On Track' : 'सञ्चालनमा', color: 'emerald' };
        if (pct >= 50) return { label: language === 'en' ? 'At Risk' : 'जोखिम', color: 'amber' };
        return { label: language === 'en' ? 'Delayed' : 'ढिलाइ', color: 'rose' };
      };

      return {
        id: afterInd.id,
        name: afterInd.name,
        nameEn: afterInd.nameEn || afterInd.name,
        beforeVal,
        afterVal,
        beforePct,
        afterPct,
        target,
        diffProgress,
        diffPct,
        beforeStatus: getStatusType(beforePct),
        afterStatus: getStatusType(afterPct),
        hasChanged: beforeVal !== afterVal
      };
    });

    // Compute aggregate changes
    const beforeWeightProg = beforeEntry?.metadata?.totalWeightProgress || 0;
    const afterWeightProg = entry?.metadata?.totalWeightProgress || 0;
    const diffWeightProg = afterWeightProg - beforeWeightProg;

    return {
      beforeEntry,
      changes,
      beforeWeightProg,
      afterWeightProg,
      diffWeightProg,
    };
  }, [entry, updatesHistory, language]);

  const toNepaliNumerals = (numStr: string | number): string => {
    const nepaliDigits = ['०', '१', '२', '३', '४', '५', '६', '७', '८', '९'];
    return String(numStr).replace(/[0-9]/g, (digit) => nepaliDigits[parseInt(digit, 10)]);
  };

  const formatNumber = (num: number, isPercentage = false): string => {
    const formatted = num.toLocaleString(undefined, { maximumFractionDigits: 1 });
    const suffix = isPercentage ? '%' : '';
    return language === 'np' ? `${toNepaliNumerals(formatted)}${suffix}` : `${formatted}${suffix}`;
  };

  const formatDate = (dateStr: string) => {
    if (!dateStr) return '';
    try {
      const d = new Date(dateStr);
      if (isNaN(d.getTime())) {
        return language === 'np' ? toNepaliNumerals(dateStr) : dateStr;
      }
      return d.toLocaleDateString(language === 'np' ? 'ne-NP' : 'en-US', {
        year: 'numeric',
        month: 'long',
        day: 'numeric',
        hour: '2-digit',
        minute: '2-digit'
      });
    } catch (e) {
      return language === 'np' ? toNepaliNumerals(dateStr) : dateStr;
    }
  };

  if (!entry || !comparisonData) return null;

  const adminEmail = entry.metadata?.updatedBy || 'coordinator.iims@gmail.com';
  const totalIndicatorsCount = entry.indicators?.length || 0;
  const changedIndicatorsCount = comparisonData.changes.filter(c => c.hasChanged).length;

  return (
    <AnimatePresence>
      {isOpen && (
        <>
          {/* Backdrop Overlay */}
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 0.5 }}
            exit={{ opacity: 0 }}
            onClick={onClose}
            className="fixed inset-0 bg-slate-950 z-[2500] backdrop-blur-sm"
            id="activity-drawer-backdrop"
          />

          {/* Drawer Slide-in container */}
          <motion.div
            initial={{ x: '100%' }}
            animate={{ x: 0 }}
            exit={{ x: '100%' }}
            transition={{ type: 'spring', damping: 25, stiffness: 220 }}
            className="fixed right-0 top-0 bottom-0 w-full max-w-2xl bg-white dark:bg-[#0f172a] shadow-2xl border-l border-slate-200 dark:border-slate-800 z-[2600] flex flex-col overflow-hidden"
            id="activity-detail-drawer"
          >
            {/* Drawer Header */}
            <div className="p-6 border-b border-slate-100 dark:border-slate-800 bg-gradient-to-r from-slate-50 to-white dark:from-slate-900 dark:to-[#0f172a]">
              <div className="flex items-center justify-between mb-4">
                <div className="flex items-center gap-2.5">
                  <div className="w-10 h-10 rounded-xl bg-indigo-50 dark:bg-indigo-950/45 text-indigo-600 dark:text-indigo-400 flex items-center justify-center shadow-inner">
                    <Database className="w-5 h-5 animate-pulse" />
                  </div>
                  <div>
                    <span className="text-[10px] font-black uppercase tracking-widest text-indigo-500 block">
                      {language === 'en' ? 'Administrative Audit Trail' : 'प्रशासकीय लेखापरीक्षण विवरण'}
                    </span>
                    <h3 className="text-base font-black text-slate-800 dark:text-slate-100 uppercase tracking-tight">
                      {language === 'en' ? 'Sync Log Comparison' : 'सिंक लग तुलना विवरण'}
                    </h3>
                  </div>
                </div>
                <button
                  onClick={onClose}
                  className="p-2 hover:bg-slate-150 dark:hover:bg-slate-800/80 text-slate-400 hover:text-slate-600 dark:hover:text-slate-300 rounded-xl transition-all cursor-pointer border border-slate-100 dark:border-slate-800/80"
                  aria-label="Close drawer"
                >
                  <X size={18} />
                </button>
              </div>

              {/* Log Metadata Banner */}
              <div className="grid grid-cols-2 gap-4 mt-4 bg-white dark:bg-slate-900 p-4 rounded-2xl border border-slate-150 dark:border-slate-800/60 shadow-inner">
                <div className="space-y-1">
                  <span className="text-[9px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-wider block">
                    {language === 'en' ? 'Synchronized By' : 'सिङ्क्रोनाइज गर्ने प्रयोगकर्ता'}
                  </span>
                  <div className="flex items-center gap-2 text-xs font-black text-slate-700 dark:text-slate-200">
                    <User size={14} className="text-indigo-500 shrink-0" />
                    <span className="truncate">{adminEmail}</span>
                  </div>
                </div>

                <div className="space-y-1">
                  <span className="text-[9px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-wider block">
                    {language === 'en' ? 'Snapshot Timestamp' : 'स्न्यापसट समय'}
                  </span>
