import React, { useEffect, useState } from 'react';
import { motion, AnimatePresence } from 'motion/react';
import { UserActivity } from '../types';
import { collection, query, orderBy, limit, onSnapshot } from 'firebase/firestore';
import { db, handleFirestoreError, OperationType } from '../firebase';
import { Activity, Clock, Search, User } from 'lucide-react';

export const ActivityTracker: React.FC = () => {
  const [activities, setActivities] = useState<UserActivity[]>([]);
  const [filterType, setFilterType] = useState<string>('all');
  const [isSearching, setIsSearching] = useState('');
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const colPath = 'activities';
    const q = query(
      collection(db, colPath),
      orderBy('timestamp', 'desc'),
      limit(100)
    );

    const unsubscribe = onSnapshot(q, (snapshot) => {
      const list: UserActivity[] = [];
      snapshot.forEach(doc => {
        const d = doc.data();
        list.push({
          id: doc.id,
          userId: d.userId,
          email: d.email,
          actionType: d.actionType,
          details: d.details,
          timestamp: d.timestamp?.seconds 
            ? new Date(d.timestamp.seconds * 1000).toISOString() 
            : d.timestamp || new Date().toISOString(),
        });
      });
      setActivities(list);
      setLoading(false);
    }, (error) => {
      // Graceful error logging as requested in skills
      try {
        handleFirestoreError(error, OperationType.GET, colPath);
      } catch (e) {
        console.error('Audit onSnapshot subscription failed:', e);
      }
      setLoading(false);
    });

    return unsubscribe;
  }, []);

  const getActionStyle = (type: UserActivity['actionType']) => {
    switch (type) {
      case 'sync_sheets': return 'bg-sky-50 text-sky-700 border-sky-100/50';
      case 'edit_indicator': return 'bg-amber-50 text-amber-700 border-amber-100/50';
      case 'role_change': return 'bg-rose-50 text-rose-700 border-rose-100/50 font-bold';
      case 'login': return 'bg-emerald-50 text-emerald-700 border-emerald-100/50';
      default: return 'bg-slate-50 text-slate-700 border-slate-100';
    }
  };

  const filtered = activities.filter(act => {
    const matchesFilter = filterType === 'all' || act.actionType === filterType;
    const matchesSearch = act.email.toLowerCase().includes(isSearching.toLowerCase()) || 
                          act.details.toLowerCase().includes(isSearching.toLowerCase());
    return matchesFilter && matchesSearch;
  });

  return (
    <div className="bg-white rounded-2xl p-5 border border-slate-100 shadow-sm" id="activity-metrics-logs">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-3 border-b border-slate-100 pb-3 mb-4">
        <div className="flex items-center gap-2">
          <Activity size={18} className="text-indigo-600 animate-pulse" />
          <h3 className="text-sm font-bold text-slate-800 font-display">प्रयोगकर्ता गतिविधि र अडिट (User Metrics & Audit Logs)</h3>
        </div>

        {/* Filters */}
        <div className="flex items-center gap-2 flex-wrap text-xs">
          <select 
            value={filterType}
            onChange={(e) => setFilterType(e.target.value)}
            className="p-1.5 rounded-lg border border-slate-200 outline-none focus:ring-1 focus:ring-indigo-500 text-xs bg-slate-50 text-slate-600"
          >
            <option value="all">All Actions</option>
            <option value="login">Logins</option>
            <option value="edit_indicator">Edits Only</option>
            <option value="sync_sheets">Sheet Syncs</option>
            <option value="role_change">Role Escalations</option>
          </select>

          <input
            type="text"
            placeholder="Search email/details..."
            value={isSearching || ''}
            onChange={(e) => setIsSearching(e.target.value)}
            className="p-1.5 rounded-lg border border-slate-200 outline-none focus:ring-1 focus:ring-indigo-500 text-xs placeholder:text-slate-400 max-w-[130px]"
          />
        </div>
      </div>

      {loading ? (
        <div className="text-center py-8 text-xs text-slate-400 animate-pulse font-sans">
          Loading audit metadata registers from Firestore...
        </div>
      ) : filtered.length === 0 ? (
        <div className="text-center py-8 text-xs text-slate-400 italic">
          No matching transaction trails discovered.
        </div>
      ) : (
        <div className="max-h-[360px] overflow-y-auto overflow-x-auto custom-scroll pr-1">
          <table className="w-full text-left text-xs min-w-[500px] md:min-w-0">
            <thead>
              <tr className="border-b border-slate-100 text-slate-400 font-sans">
                <th className="pb-2 font-semibold">User (इमेल)</th>
                <th className="pb-2 font-semibold text-center">Action (कार्य)</th>
                <th className="pb-2 font-semibold">Details (विवरण)</th>
                <th className="pb-2 font-semibold text-right">Time (समय)</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100 relative">
              <AnimatePresence mode="popLayout" initial={false}>
                {filtered.map((act) => (
                  <motion.tr 
                    key={act.id} 
                    layout
                    initial={{ opacity: 0, y: 10 }}
                    animate={{ opacity: 1, y: 0 }}
                    exit={{ opacity: 0, scale: 0.98, transition: { duration: 0.2 } }}
                    className="hover:bg-slate-50/50 transition-colors"
                  >
                    <td className="py-2.5 max-w-[140px] truncate pr-2 font-medium text-slate-700" title={act.email}>
                      {act.email}
                    </td>
                    <td className="py-2.5 text-center pr-2">
                      <span className={`text-[9px] uppercase font-bold tracking-wider px-2 py-0.5 rounded border ${getActionStyle(act.actionType)}`}>
                        {act.actionType}
                      </span>
                    </td>
                    <td className="py-2.5 text-slate-600 pr-2 leading-snug">
                      {act.details}
                    </td>
                    <td className="py-2.5 text-right font-mono text-[10px] text-slate-400 shrink-0">
                      {new Date(act.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' })}
                    </td>
                  </motion.tr>
                ))}
              </AnimatePresence>
            </tbody>
          </table>
        </div>
      )}

      <div className="pt-3 border-t border-slate-50 mt-3 text-[10px] text-slate-400 flex items-center justify-between">
        <span className="flex items-center gap-1">
          <Clock size={12} />
          Append-only secure log chain
        </span>
        <span className="font-semibold text-indigo-600 font-mono">
          {filtered.length} trails shown
        </span>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { useAuth } from '../context/AuthContext';
import { AdminUser } from '../types';
import { doc, setDoc, deleteDoc, serverTimestamp } from 'firebase/firestore';
import { db } from '../firebase';
import { Shield, Trash2, UserPlus, CheckCircle, AlertCircle } from 'lucide-react';

export const AdminMgmt: React.FC = () => {
  const { adminsList, isSuperadmin, logActivity, refreshAdmins, user } = useAuth();
  const [newEmail, setNewEmail] = useState('');
  const [newUid, setNewUid] = useState('');
  const [newRole, setNewRole] = useState<'admin' | 'superadmin'>('admin');
  const [errorMsg, setErrorMsg] = useState('');
  const [successMsg, setSuccessMsg] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);

  // Promote action handler
  const handleAddAdmin = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newEmail || !newUid) {
      setErrorMsg('Please enter both Email and Firebase UID or temporary ID string.');
      return;
    }
    setErrorMsg('');
    setSuccessMsg('');
    setIsSubmitting(true);

    try {
      const adminId = newUid.trim();
      const adminEmail = newEmail.trim().toLowerCase();

      await setDoc(doc(db, 'admins', adminId), {
        email: adminEmail,
        role: newRole,
        createdAt: serverTimestamp(),
      });

      await logActivity('role_change', `Upgraded ${adminEmail} to ${newRole}`);
      setSuccessMsg(`Successfully assigned role ${newRole} to ${adminEmail}!`);
      setNewEmail('');
      setNewUid('');
      await refreshAdmins();
    } catch (err) {
      console.error(err);
      setErrorMsg('Database update failed. Ensure you are signed in as Superadmin.');
    } finally {
      setIsSubmitting(false);
    }
  };

  // Demote/Delete handler
  const handleDeleteAdmin = async (targetUid: string, targetEmail: string) => {
    if (targetEmail === 'banjays@gmail.com') {
      setErrorMsg('Cannot remove the root bootstrapped superadmin!');
      return;
    }
    if (targetUid === user?.uid) {
      setErrorMsg('Cannot remove your own admin status!');
      return;
    }

    if (!window.confirm(`Are you sure you want to revoke admin rights for ${targetEmail}?`)) {
      return;
    }

    setErrorMsg('');
    setSuccessMsg('');

    try {
      await deleteDoc(doc(db, 'admins', targetUid));
      await logActivity('role_change', `Revoked access of ${targetEmail}`);
      setSuccessMsg(`Revoked admin permissions for ${targetEmail}.`);
      await refreshAdmins();
    } catch (err) {
      console.error(err);
      setErrorMsg('Failed to delete administrator role.');
    }
  };

  if (!isSuperadmin) {
    return (
      <div className="bg-amber-50 rounded-2xl p-6 border border-amber-200 text-amber-800 text-center space-y-2 mt-4">
        <AlertCircle className="mx-auto text-amber-600" size={32} />
        <h4 className="font-bold font-display">सुपरएडमिन पहुँच सीमित छ (Superadmin Restricted Area)</h4>
        <p className="text-xs max-w-sm mx-auto">
          Role-Based Access Controls permit only accounts designated as Superadmin to manage user registrations and roles.
        </p>
      </div>
    );
  }

  return (
    <div className="space-y-6 mt-4" id="admin-management-module">

      {/* ROLE ASSIGNMENT FORM */}
      <div className="bg-white rounded-2xl p-5 border border-slate-100 shadow-sm" id="role-invite-form">
        <div className="flex items-center gap-2 border-b border-slate-50 pb-3 mb-4">
          <UserPlus size={18} className="text-indigo-600" />
          <h3 className="text-sm font-bold text-slate-800 font-display">नयाँ अनुमति जारी गर्नुहोस् (Grant Elevated Rights)</h3>
        </div>

        {errorMsg && (
          <div className="bg-rose-50 border border-rose-100 text-rose-700 p-2.5 rounded-lg text-xs font-sans mb-3 flex items-center gap-2">
            <AlertCircle size={14} className="shrink-0" />
            <span>{errorMsg}</span>
          </div>
        )}

        {successMsg && (
          <div className="bg-emerald-50 border border-emerald-100 text-emerald-800 p-2.5 rounded-lg text-xs font-sans mb-3 flex items-center gap-2">
            <CheckCircle size={14} className="shrink-0 animate-bounce" />
            <span>{successMsg}</span>
          </div>
        )}

        <form onSubmit={handleAddAdmin} className="space-y-3.5">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
            <div>
              <label className="text-[10px] uppercase tracking-wider text-slate-400 font-semibold block mb-1">UID (Firebase Auth Uid)</label>
              <input
                type="text"
                placeholder="User's UID"
                value={newUid || ''}
                onChange={(e) => setNewUid(e.target.value)}
                className="w-full text-xs p-2.5 rounded-xl border border-slate-200 focus:outline-none focus:ring-2 focus:ring-indigo-500 bg-slate-50/50"
              />
            </div>
            <div>
