        </div>
      )}
    </motion.div>
  );
});

import React, { useState } from 'react';
import { Indicator } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell, PieChart as RechartsPie, Pie, RadialBarChart, RadialBar, Legend } from 'recharts';
import { LayoutDashboard, BarChart3, PieChart, Target, ShieldCheck } from 'lucide-react';
import { useLanguage } from '../context/LanguageContext';
import { triggerHaptic } from '../utils/haptic';
import { normalizeCategory } from '../utils/category';

interface ChartProps {
  indicators: Indicator[];
}

const CATEGORY_COLORS: Record<string, string> = {
  "Infrastructure Creation": "#6366f1",
  "Maintenance": "#3b82f6",
  "Employment Creation": "#10b981",
  "Budget Utilization": "#f59e0b",
  "Governance": "#ec4899"
};

export const CategoryPerformanceChart: React.FC<ChartProps> = ({ indicators }) => {
  const { language, t } = useLanguage();
  const [selectedCategory, setSelectedCategory] = React.useState<string | null>(null);
  const [chartType, setChartType] = useState<'bar' | 'pie' | 'radial'>('bar');

  // Group and calculate averages
  const categoryData = indicators.reduce((acc: Record<string, { totalPercent: number, count: number }>, ind) => {
    const cat = normalizeCategory(ind.category);
    if (!acc[cat]) {
      acc[cat] = { totalPercent: 0, count: 0 };
    }
    const percent = ind.annualTarget > 0 ? Math.min(100, Math.round((ind.annualProgress / ind.annualTarget) * 100)) : 0;
    acc[cat].totalPercent += percent;
    acc[cat].count += 1;
    return acc;
  }, {});

  const chartData = Object.entries(categoryData).map(([name, data]: [string, { totalPercent: number, count: number }]) => {
    const avg = Math.round(data.totalPercent / data.count);
    return {
      name: name, // Keep raw name for matching
      displayName: t(name),
      average: avg === 0 ? 1 : avg,
      actualAverage: avg
    };
  }).sort((a, b) => b.average - a.average);

  const breakdownData = selectedCategory ? indicators
    .filter(ind => normalizeCategory(ind.category) === selectedCategory)
    .map(ind => {
      const percent = ind.annualTarget > 0 ? Math.min(100, Math.round((ind.annualProgress / ind.annualTarget) * 100)) : 0;
      return {
        name: language === 'en' ? ind.nameEn : ind.name,
        weight: ind.weight || 0,
        progress: percent === 0 ? 1 : percent,
        actualProgress: percent
      };
    }) : [];

  const govIndicators = indicators.filter(ind => normalizeCategory(ind.category) === 'Governance');
  const govAvg = categoryData['Governance'] 
    ? Math.round(categoryData['Governance'].totalPercent / categoryData['Governance'].count)
    : 0;

  const renderChart = () => {
    const dataToRender = selectedCategory ? breakdownData : chartData;
    const dataKey = selectedCategory ? 'progress' : 'average';
    const nameKey = selectedCategory ? 'name' : 'displayName';

    if (chartType === 'pie') {
        return (
            <ResponsiveContainer width="100%" height="100%">
                <RechartsPie>
                    <Pie data={dataToRender} dataKey={dataKey} nameKey={nameKey} cx="50%" cy="50%" outerRadius={80} fill="#ec4899" label>
                      {dataToRender.map((entry: any, index) => {
                          const catKey = selectedCategory ? selectedCategory : entry.name;
                          const color = CATEGORY_COLORS[catKey] || "#8b5cf6";
                          return <Cell key={`cell-${index}`} fill={color} />;
                      })}
                    </Pie>
                    <Tooltip formatter={(value: any, name: any, props: any) => {
                      const payload = props.payload;
                      const displayValue = (payload && payload.actualAverage !== undefined) 
                        ? payload.actualAverage 
                        : (payload && payload.actualProgress !== undefined) 
                          ? payload.actualProgress 
                          : value;
                      return [`${displayValue}%`, name];
                    }} />
                    <Legend />
                </RechartsPie>
            </ResponsiveContainer>
        );
    }

    if (chartType === 'radial') {
        return (
            <ResponsiveContainer width="100%" height="100%">
                <RadialBarChart cx="50%" cy="50%" innerRadius="20%" outerRadius="80%" barSize={10} data={dataToRender}>
                    <RadialBar label={{ position: 'insideStart', fill: '#fff' }} background dataKey={dataKey}>
                      {dataToRender.map((entry: any, index) => {
                          const catKey = selectedCategory ? selectedCategory : entry.name;
                          const color = CATEGORY_COLORS[catKey] || "#8b5cf6";
                          return <Cell key={`cell-${index}`} fill={color} />;
                      })}
                    </RadialBar>
                    <Legend iconSize={10} layout="vertical" verticalAlign="middle" wrapperStyle={{right: 0}} />
                    <Tooltip formatter={(value: any, name: any, props: any) => {
                      const payload = props.payload;
                      const displayValue = (payload && payload.actualAverage !== undefined) 
                        ? payload.actualAverage 
                        : (payload && payload.actualProgress !== undefined) 
                          ? payload.actualProgress 
                          : value;
                      return [`${displayValue}%`, name];
                    }} />
                </RadialBarChart>
            </ResponsiveContainer>
        );
    }

    return (
        <ResponsiveContainer width="100%" height="100%">
            <BarChart data={dataToRender} layout="vertical" margin={{ top: 5, right: 30, left: selectedCategory ? 50 : 20, bottom: 5 }}>
                <CartesianGrid strokeDasharray="3 3" horizontal={true} vertical={false} />
                <XAxis type="number" domain={[0, 100]} unit="%" />
                <YAxis type="category" dataKey={nameKey} width={selectedCategory ? 150 : 100} tick={{ fontSize: selectedCategory ? 8 : 10 }} />
                <Tooltip formatter={(value: any, name: any, props: any) => {
                  const payload = props.payload;
                  const displayValue = (payload && payload.actualAverage !== undefined) 
                    ? payload.actualAverage 
                    : (payload && payload.actualProgress !== undefined) 
                      ? payload.actualProgress 
                      : value;
                  return [`${displayValue}%`, name];
                }} />
                <Bar 
                    dataKey={dataKey} 
                    radius={[0, 4, 4, 0]} 
                    barSize={20} 
                    onClick={(data) => {
                        if (!selectedCategory) {
                            setSelectedCategory(data.name);
                            triggerHaptic('medium');
                        }
                    }}
                    onMouseEnter={() => triggerHaptic('light')}
                >
                    {dataToRender.map((entry: any, index) => {
                        const catKey = selectedCategory ? selectedCategory : entry.name;
                        const color = CATEGORY_COLORS[catKey] || "#ec4899";
                        return <Cell key={`cell-${index}`} fill={color} className={!selectedCategory ? "cursor-pointer" : ""} />;
                    })}
                </Bar>
            </BarChart>
        </ResponsiveContainer>
    );
  };

  return (
    <div className="bg-white dark:bg-slate-900 rounded-3xl p-6 border border-slate-200 dark:border-slate-800 shadow-sm col-span-12 lg:col-span-6">
      <div className="flex items-center justify-between mb-6">
        <div className="flex items-center gap-3">
          <div 
            className="p-2 bg-purple-50 dark:bg-purple-900/30 rounded-lg cursor-pointer" 
            onClick={() => {
                setSelectedCategory(null);
                triggerHaptic('medium');
            }}
          >
            <LayoutDashboard size={20} className="text-purple-600 dark:text-purple-400" />
          </div>
          <div>
            <h3 className="text-base font-bold text-slate-800 dark:text-slate-100 font-display">
              {selectedCategory ? t(selectedCategory) : t('categoryPerformance')}
            </h3>
            <p className="text-[10px] text-slate-500 uppercase tracking-wider font-semibold">
              {selectedCategory ? t('indicatorBreakdown') : t('averageProgressByCategory')}
            </p>
          </div>
        </div>
        <div className="flex gap-2">
            <button onClick={() => { setChartType('bar'); triggerHaptic('light'); }} className={`p-1.5 rounded ${chartType === 'bar' ? 'bg-purple-100 text-purple-700' : 'text-slate-400'}`}><BarChart3 size={16}/></button>
            <button onClick={() => { setChartType('pie'); triggerHaptic('light'); }} className={`p-1.5 rounded ${chartType === 'pie' ? 'bg-purple-100 text-purple-700' : 'text-slate-400'}`}><PieChart size={16}/></button>
            <button onClick={() => { setChartType('radial'); triggerHaptic('light'); }} className={`p-1.5 rounded ${chartType === 'radial' ? 'bg-purple-100 text-purple-700' : 'text-slate-400'}`}><Target size={16}/></button>
        </div>
      </div>

      <div className="h-[300px] w-full relative">
        {renderChart()}
        {selectedCategory && (
            <div className="absolute bottom-2 left-2">
                <button 
                  onClick={() => {
                    const cardsElement = document.getElementById('indicators-section');
                    cardsElement?.scrollIntoView({ behavior: 'smooth' });
                  }}
                  className="text-[10px] bg-indigo-600 text-white px-3 py-1.5 rounded-full hover:bg-indigo-700 transition-colors"
                >
                    {t('viewRelatedCards') || 'View Related Indicators'}
                </button>
            </div>
        )}
      </div>

      {/* Governance & Auditing Live Status Card */}
      <div className="mt-6 pt-6 border-t border-slate-150 dark:border-slate-800">
        <div className="flex items-center justify-between mb-4">
          <div className="flex items-center gap-2">
            <ShieldCheck size={18} className="text-pink-500 animate-pulse" />
            <span className="text-xs font-black uppercase tracking-wider text-slate-800 dark:text-slate-200">
              {t('Governance')}
            </span>
          </div>
          <span className="text-xs font-bold text-pink-600 dark:text-pink-400 bg-pink-50 dark:bg-pink-950/40 px-2.5 py-1 rounded-lg">
            {t('average') || 'Average'}: {govAvg}%
          </span>
        </div>
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
          {govIndicators.map(ind => {
            const percent = ind.annualTarget > 0 ? Math.min(100, Math.round((ind.annualProgress / ind.annualTarget) * 100)) : 0;
            return (
              <div key={ind.id} className="bg-slate-50 dark:bg-slate-800/40 border border-slate-100 dark:border-slate-800/60 rounded-2xl p-3 flex flex-col justify-between">
                <div>
                  <h4 className="text-[11px] font-bold text-slate-700 dark:text-slate-300 line-clamp-1">
                    {language === 'en' ? ind.nameEn : ind.name}
                  </h4>
                  <div className="flex items-baseline gap-1 mt-1">
                    <span className="text-sm font-black text-slate-800 dark:text-slate-100">{ind.annualProgress}</span>
                    <span className="text-[10px] font-medium text-slate-400">/ {ind.annualTarget} {ind.unit}</span>
                  </div>
                </div>
                <div className="mt-2">
                  <div className="flex items-center justify-between text-[9px] font-bold text-slate-400 uppercase mb-1">
                    <span>{t('completion') || 'Completion'}</span>
                    <span className="text-pink-600 dark:text-pink-400">{percent}%</span>
                  </div>
                  <div className="w-full h-1.5 bg-slate-200 dark:bg-slate-800 rounded-full overflow-hidden">
                    <div className="h-full rounded-full bg-pink-500" style={{ width: `${percent}%` }} />
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useMemo } from "react";
import { Indicator } from "../types";
import { useLanguage } from "../context/LanguageContext";
import { normalizeCategory, STANDARD_CATEGORIES } from "../utils/category";
import {
  ResponsiveContainer,
  LineChart,
  Line,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
} from "recharts";
import {
  TrendingUp,
  Layers,
  Sparkles,
  Info,
  Calendar,
  CheckCircle2,
  ArrowUpRight,
  Filter,
} from "lucide-react";
import { motion } from "motion/react";
import { triggerHaptic } from "../utils/haptic";

interface CategoryTrendViewProps {
  indicators: Indicator[];
  updatesHistory: any[];
}

const toNepaliNumerals = (numStr: string | number): string => {
  const nepaliDigits = ["०", "१", "२", "३", "४", "५", "६", "७", "८", "९"];
  return String(numStr).replace(/[0-9]/g, (match) => nepaliDigits[parseInt(match, 10)]);
};

