  string,
  { stroke: string; labelEn: string; labelNp: string; bgClass: string; textClass: string; borderClass: string }
> = {
  "Infrastructure Creation": {
    stroke: "#6366f1", // Indigo
    labelEn: "Infrastructure Creation",
    labelNp: "भौतिक पूर्वाधार निर्माण",
