    labelEn: "Governance & Auditing",
    labelNp: "सुशासन र संस्थागत सबलीकरण",
    bgClass: "bg-pink-50 dark:bg-pink-950/30",
    textClass: "text-pink-600 dark:text-pink-400",
    borderClass: "border-pink-200 dark:border-pink-900/50",
  },
};

export const CategoryTrendView: React.FC<CategoryTrendViewProps> = ({
  indicators,
  updatesHistory,
}) => {
  const { language, t } = useLanguage();
  const [activeCategories, setActiveCategories] = useState<Set<string>>(
    () => new Set(STANDARD_CATEGORIES)
  );

  // Parse time series data (chronological order)
  const trendData = useMemo(() => {
    if (!updatesHistory || updatesHistory.length === 0) return [];

    // Sort oldest first
    const chronHistory = [...updatesHistory].sort((a, b) => {
      const aTime = new Date(a.createdAt || a.id).getTime();
      const bTime = new Date(b.createdAt || b.id).getTime();
      return aTime - bTime;
    });

    return chronHistory.map((entry) => {
      const snapshotIndicators = (entry.indicators || []) as Indicator[];

      // Initialize lists
      const catProgress: Record<string, number[]> = {};
      STANDARD_CATEGORIES.forEach((c) => {
        catProgress[c] = [];
      });

      // Group and normalize progress
      snapshotIndicators.forEach((ind: Indicator) => {
        const category = normalizeCategory(ind.category);
        if (catProgress[category] !== undefined) {
          const progress =
            ind.annualTarget > 0
              ? (ind.annualProgress / ind.annualTarget) * 100
              : 0;
          catProgress[category].push(progress);
        }
      });

      // Create entry record
      const entryData: any = {
        id: entry.id,
        rawDate: entry.createdAt || entry.lastUpdateDate || entry.id,
        formattedDate: new Date(entry.createdAt || entry.lastUpdateDate || entry.id).toLocaleDateString(
          language === "en" ? "en-US" : "ne-NP",
          { month: "short", day: "numeric" }
        ),
      };

      // Compute averages
      STANDARD_CATEGORIES.forEach((c) => {
        const values = catProgress[c];
        entryData[c] =
          values.length > 0
            ? Math.round(values.reduce((sum, v) => sum + v, 0) / values.length)
            : 0;
      });

      return entryData;
    });
  }, [updatesHistory, language]);

  // Handle toggling of line series on/off
  const toggleCategory = (category: string) => {
    triggerHaptic("light");
    setActiveCategories((prev) => {
      const next = new Set(prev);
      if (next.has(category)) {
        // Prevent clearing the very last visible category to keep chart populated
        if (next.size > 1) {
          next.delete(category);
        }
      } else {
        next.add(category);
      }
      return next;
    });
  };

  // Calculate high-level insights for the trends
  const trendInsights = useMemo(() => {
    if (trendData.length < 2) return null;

    const firstEntry = trendData[0];
    const lastEntry = trendData[trendData.length - 1];

    let highestValue = -1;
    let highestCat = "";
    let fastestGrowth = -999;
    let fastestGrowthCat = "";

    STANDARD_CATEGORIES.forEach((c) => {
      const startVal = firstEntry[c] || 0;
      const endVal = lastEntry[c] || 0;
      const growth = endVal - startVal;

      if (endVal > highestValue) {
        highestValue = endVal;
        highestCat = c;
      }

      if (growth > fastestGrowth) {
        fastestGrowth = growth;
        fastestGrowthCat = c;
      }
    });

    return {
      highestValue,
      highestCat,
      fastestGrowth,
      fastestGrowthCat,
    };
  }, [trendData]);

  const formatNumber = (num: number): string => {
    return language === "en" ? `${num}%` : `${toNepaliNumerals(num)}%`;
  };

  // Custom tooltip to support translation and theme styles
  const CustomTooltip = ({ active, payload, label }: any) => {
    if (active && payload && payload.length) {
      return (
        <div className="bg-slate-900/95 dark:bg-slate-950/95 backdrop-blur-xl border border-indigo-500/30 p-4 rounded-2xl shadow-2xl text-white text-xs space-y-2.5 min-w-[200px] z-50">
          <div className="flex items-center gap-1.5 border-b border-white/10 pb-1.5 font-bold text-slate-300">
            <Calendar size={13} className="text-indigo-400" />
            <span>{label}</span>
          </div>
          <div className="space-y-1.5">
            {payload.map((item: any) => {
              const style = CATEGORY_STYLES[item.name] || {
                stroke: "#cbd5e1",
                labelEn: item.name,
                labelNp: item.name,
                bgClass: "bg-slate-50 dark:bg-slate-900/50",
                textClass: "text-slate-500",
                borderClass: "border-slate-200 dark:border-slate-800",
              };
              const categoryName = language === "en" ? style.labelEn : style.labelNp;
              return (
