            {language === 'en' ? 'Customize Followed Indicators' : 'सूचकहरूको अनुगमन अनुकूलन गर्नुहोस्'}
          </span>
          <ArrowRight size={12} className="animate-pulse" />
        </button>
      </div>
    </div>
  );
};

