const toNepaliNumerals = (numStr: string | number): string => {
  const nepaliDigits = ['०', '१', '२', '३', '४', '५', '६', '७', '८', '९'];
  return String(numStr).replace(/[0-9]/g, (digit) => nepaliDigits[parseInt(digit, 10)]);
};

const AnimatedNumber: React.FC<{
  value: number;
  isNepali: boolean;
  suffix?: string;
  className?: string;
}> = ({ value, isNepali, suffix = '', className = '' }) => {
  const [displayValue, setDisplayValue] = React.useState<number>(0);
  const previousValue = React.useRef<number>(0);

  React.useEffect(() => {
    let startTimestamp: number | null = null;
    const duration = 800; // ms transition duration for dynamic and snappy counting
    const startValue = previousValue.current;
    const endValue = value;

    if (startValue === endValue) {
      setDisplayValue(endValue);
      return;
    }

    let animationFrameId: number;

    const step = (timestamp: number) => {
      if (!startTimestamp) startTimestamp = timestamp;
      const elapsed = timestamp - startTimestamp;
      const progress = Math.min(elapsed / duration, 1);

      // Easing function (easeOutQuad) for natural dynamic motion
      const easeProgress = progress * (2 - progress);
      const currentValue = startValue + (endValue - startValue) * easeProgress;

      setDisplayValue(Math.round(currentValue));

      if (progress < 1) {
        animationFrameId = requestAnimationFrame(step);
      } else {
        setDisplayValue(endValue);
        previousValue.current = endValue;
      }
    };

    animationFrameId = requestAnimationFrame(step);
    return () => cancelAnimationFrame(animationFrameId);
  }, [value]);

  const formatted = isNepali ? toNepaliNumerals(displayValue) : displayValue.toString();

  return <span className={className}>{formatted}{suffix}</span>;
};

