      matchedView = 'table';
      viewFeedbackEn = 'Switching to Table View.';
      viewFeedbackNp = 'तालिका दृश्यमा जाँदैछ।';
    } else if (
      normalized.includes('card view') ||
      normalized.includes('show card') ||
      normalized.includes('go to card') ||
