import React, { useState, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'motion/react';
import { Sun, Moon, Monitor, Languages, Wifi, WifiOff, RefreshCw, Menu, X, Globe, Phone, Info, ExternalLink, FileText, Map as MapIcon, CloudUpload, AlertCircle, Clock, Database, Type, Settings, Square, Ghost, LayoutGrid, Scale, Coins, Wallet, Shield, Check, Volume2, Search } from 'lucide-react';
import { AreaChart, Area, ResponsiveContainer } from 'recharts';
import { useLanguage } from '../context/LanguageContext';
import { triggerHaptic } from '../utils/haptic';
import { speak } from '../utils/speech';
import { useAuth } from '../context/AuthContext';
import { useTextScale, TextScale } from '../hooks/useTextScale';
import { doc, getDoc, setDoc } from 'firebase/firestore';
import { db } from '../firebase';
import { SearchDropdown } from './SearchDropdown';
import { APP_TITLES } from '../constants/appTitles';

interface HeaderProps {
  lastUpdateDate?: string;
  pulseKey?: number;
  onOpenMap?: () => void;
  isOnline?: boolean;
  pendingWrites?: { id: string; name: string; nameEn: string }[];
  offices?: { name: string; updated: string }[];
  onOpenAbout?: () => void;
  onMouseEnterAbout?: () => void;
  onMouseLeaveAbout?: () => void;
  isAtBottom?: boolean;
  searchQuery?: string;
  onSearch?: (query: string) => void;
  sortType?: 'default' | 'low' | 'high';
  onSortChange?: (type: 'default' | 'low' | 'high') => void;
  onViewChange?: (view: any) => void;
  selectedCategory?: string;
  onCategoryChange?: (category: string) => void;
  showMilestonesOnly?: boolean;
  onToggleMilestonesOnly?: () => void;
  viewMode?: any;
  viewOptions?: any;
  indicators?: any[];
  metadata?: any;
  trackedIds?: string[];
  onToggleTrack?: (id: string) => void;
  updatesHistory?: any[];
  selectedOffice?: string;
  onOfficeChange?: (office: string) => void;
}

const getSyncedAgoText = (diffMs: number, lang: 'en' | 'ne'): string => {
  const diffSec = Math.floor(diffMs / 1000);
  const diffMin = Math.floor(diffSec / 60);

  if (lang === 'ne') {
    if (diffMin < 1) {
      return 'भर्खरै';
    }
    if (diffMin === 1) {
      return '१ मिनेट अघि';
    }
    // Convert minutes to Nepali numerals
    const nepaliNumerals: Record<string, string> = {
      '0': '०', '1': '१', '2': '२', '3': '३', '4': '४',
      '5': '५', '6': '६', '7': '७', '8': '८', '9': '९'
    };
    const nepaliMin = String(diffMin).split('').map(digit => nepaliNumerals[digit] || digit).join('');
    return `${nepaliMin} मिनेट अघि`;
  } else {
    if (diffMin < 1) {
      return 'just now';
    }
    if (diffMin === 1) {
      return '1 minute ago';
    }
    return `${diffMin} minutes ago`;
  }
};

export const Header: React.FC<HeaderProps> = ({ 
  lastUpdateDate = '2083/02/30',
  pulseKey = 0,
  onOpenMap,
  isOnline = true,
  pendingWrites = [],
  offices = [],
  onOpenAbout,
  onMouseEnterAbout,
  onMouseLeaveAbout,
  isAtBottom = false,
  searchQuery = '',
  onSearch = () => {},
  sortType = 'default',
  onSortChange = () => {},
  onViewChange = () => {},
  selectedCategory = 'All',
  onCategoryChange = (category: string) => {},
  showMilestonesOnly = false,
  onToggleMilestonesOnly = () => {},
  viewMode = 'dashboard',
  viewOptions = [],
  indicators = [],
  metadata = null,
  trackedIds = [],
  onToggleTrack = (id: string) => {},
  updatesHistory = [],
  selectedOffice = 'All',
  onOfficeChange = (office: string) => {}
}) => {
  const { language, setLanguage, t } = useLanguage();
  const [lastSyncedTime, setLastSyncedTime] = useState<Date>(() => new Date());
  const [isPendingWritesOpen, setIsPendingWritesOpen] = useState(false);
  const [syncedAgoText, setSyncedAgoText] = useState<string>('');

  const sparklineData = React.useMemo(() => {
    if (!updatesHistory || updatesHistory.length === 0) return [];
    const sortedHistory = [...updatesHistory].sort((a, b) => 
        new Date(a.createdAt || a.id).getTime() - new Date(b.createdAt || b.id).getTime()
    );
    return sortedHistory.map(historyItem => {
        const indicators = historyItem.indicators || [];
        const totalTarget = indicators.reduce((sum: number, ind: any) => sum + (ind.annualTarget || 0), 0);
        const totalProgress = indicators.reduce((sum: number, ind: any) => sum + (ind.annualProgress || 0), 0);
        return {
            percent: totalTarget > 0 ? Math.round((totalProgress / totalTarget) * 100) : 0
        };
    });
  }, [updatesHistory]);

  useEffect(() => {
    setLastSyncedTime(new Date());
  }, [pulseKey]);

  useEffect(() => {
    const updateText = () => {
      const diffMs = new Date().getTime() - lastSyncedTime.getTime();
      setSyncedAgoText(getSyncedAgoText(diffMs, language));
    };

    updateText(); // run once immediately
    const interval = setInterval(updateText, 10000); // update every 10 seconds

    return () => clearInterval(interval);
  }, [lastSyncedTime, language]);

  type ThemePref = 'light' | 'dark' | 'system';
  const { user } = useAuth();
  const [hasLoadedFromFirestore, setHasLoadedFromFirestore] = useState(false);

  const [themePref, setThemePref] = useState<ThemePref>(() => {
    if (typeof window !== 'undefined') {
      try {
        const saved = localStorage.getItem('theme');
        if (saved === 'light' || saved === 'dark' || saved === 'system') {
          return saved as ThemePref;
        }
      } catch (e) {
        // Suppress redundant log
      }
    }
    return 'light';
  });

  // Sync theme with Firestore when authenticated user logs in
  useEffect(() => {
    if (!user) {
      setHasLoadedFromFirestore(false);
      return;
    }

    let isSubscribed = true;
    const fetchUserTheme = async () => {
      try {
        const userRef = doc(db, 'users', user.uid);
        const userSnap = await getDoc(userRef);
        if (userSnap.exists() && isSubscribed) {
          const data = userSnap.data();
          if (data && (data.theme === 'light' || data.theme === 'dark' || data.theme === 'system')) {
            setThemePref(data.theme);
          }
        }
      } catch (err) {
        console.error('Error fetching user theme preference:', err);
      } finally {
        if (isSubscribed) {
          setHasLoadedFromFirestore(true);
        }
      }
    };

    fetchUserTheme();
    return () => {
      isSubscribed = false;
    };
  }, [user]);

  // Save to Firestore when themePref changes and user is logged in
  useEffect(() => {
    if (!user) return;
    if (!hasLoadedFromFirestore) return;

    const saveThemeToFirestore = async () => {
      try {
        const userRef = doc(db, 'users', user.uid);
        await setDoc(userRef, { theme: themePref }, { merge: true });
      } catch (err) {
        console.error('Error saving user theme preference:', err);
      }
    };

    saveThemeToFirestore();
  }, [themePref, user, hasLoadedFromFirestore]);

  useEffect(() => {
    const root = window.document.documentElement;
    const mediaQuery = window.matchMedia('(prefers-color-scheme: dark)');

    const applyTheme = () => {
      let isDark = false;
      if (themePref === 'dark') {
        isDark = true;
      } else if (themePref === 'system') {
        isDark = mediaQuery.matches;
      }

      if (isDark) {
        root.classList.add('dark');
      } else {
        root.classList.remove('dark');
      }

      try {
        localStorage.setItem('theme', themePref);
      } catch (e) {
        // Suppress redundant log
      }
    };

    applyTheme();

    const handleChange = () => {
      if (themePref === 'system') {
        applyTheme();
      }
    };

    mediaQuery.addEventListener('change', handleChange);
    return () => mediaQuery.removeEventListener('change', handleChange);
  }, [themePref]);

  const [scrolled, setScrolled] = useState(false);
  const lastScrollY = useRef(0);
  const [isMobile, setIsMobile] = useState(typeof window !== 'undefined' ? window.innerWidth < 768 : false);
  const [isSearchVisible, setIsSearchVisible] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      const currentScrollY = window.scrollY;

      // Scrolled threshold for visual change
      setScrolled(currentScrollY > 20);

      lastScrollY.current = currentScrollY;
    };
    window.addEventListener('scroll', handleScroll, { passive: true });
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  useEffect(() => {
    const handleResize = () => {
      setIsMobile(window.innerWidth < 768);
    };
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  const { textScale, setTextScale, autoAdjust, setAutoAdjust, highContrast, setHighContrast } = useTextScale();
  const [isScaleDropdownOpen, setIsScaleDropdownOpen] = useState(false);
  const [headerStyle, setHeaderStyle] = useState<'auto' | 'bold' | 'trans'>('auto');

  const toggleTheme = () => {
    triggerHaptic('medium');
    if (themePref === 'light') {
      setThemePref('dark');
    } else if (themePref === 'dark') {
      setThemePref('system');
    } else {
      setThemePref('light');
    }
  };

  const getThemeIcon = () => {
    if (themePref === 'dark') return <Moon className="w-3 sm:w-4 h-3 sm:h-4" fill="currentColor" />;
    if (themePref === 'system') return <Monitor className="w-3 sm:w-4 h-3 sm:h-4" />;
    return <Sun className="w-3 sm:w-4 h-3 sm:h-4" />;
  };

  const getHeaderBg = () => {
    if (headerStyle === 'bold') return 'bg-cyan-50/95 dark:bg-slate-900/95 shadow-md border-b border-cyan-100 dark:border-white/10';
    if (headerStyle === 'trans') return 'bg-transparent border-b border-transparent';

    return 'bg-cyan-50/95 dark:bg-slate-900/95 shadow-md border-b border-cyan-100 dark:border-white/10';
  };

  const headerBg = getHeaderBg();

  return (
    <header 
      className={`w-full sticky top-0 z-[100] transition-all duration-500 ${headerBg} shadow-md ${
        scrolled ? 'h-[56px] sm:h-[64px]' : 'h-[115px] sm:h-[135px]'
      } flex items-center overflow-hidden`}
    >
      {/* Small, persistent 'Offline' visual banner */}
      {!isOnline && (
        <div 
          className="absolute top-0 left-0 right-0 h-1 bg-rose-500 dark:bg-rose-600 shadow-[0_1px_8px_rgba(244,63,94,0.6)] animate-pulse z-[110]"
          title={language === 'en' ? 'System Offline' : 'प्रणाली अफलाइन'}
        />
      )}
      <div className="container mx-auto px-4 max-w-7xl">
        <div className="flex flex-col gap-0.5 sm:gap-1">
          <div className="flex items-center justify-between gap-4 h-14 sm:h-16">
            <div className="flex items-center gap-3 sm:gap-4 flex-1 min-w-0">
              {!isSearchVisible ? (
                <>
                  {/* Government Logo */}
                  <motion.div
                    whileHover={{ scale: 1.05 }}
                    className={`relative shrink-0 flex items-center justify-center transition-all duration-500 ${
                      scrolled ? 'w-6 h-6 sm:w-8 sm:h-8' : 'w-8 h-8 sm:w-10 sm:h-10'
                    }`}
                  >
                    <img 
                      src="/GovtLogo.svg" 
                      alt="Government of Nepal Logo" 
                      className="w-full h-full object-contain filter drop-shadow-sm"
                      referrerPolicy="no-referrer"
                    />
                    {isOnline ? (
                      <span 
                        className="absolute -bottom-0.5 -right-0.5 rounded-full border-2 border-white dark:border-[#0c152e] bg-emerald-500 shadow-sm z-10 w-2.5 h-2.5"
                        title={language === 'en' ? 'System Online' : 'प्रणाली अनलाइन'}
                      />
                    ) : (
                      <span 
                        className="absolute -bottom-1 -right-1 w-4 h-4 z-10 flex items-center justify-center cursor-help"
                        title={language === 'en' ? 'System Offline - Changes saved to local cache' : 'प्रणाली अफलाइन - परिवर्तनहरू स्थानीय क्यासमा सुरक्षित छन्'}
                      >
                        <span className="absolute inline-flex h-full w-full rounded-full bg-rose-500 opacity-75 animate-ping" />
                        <span className="relative inline-flex rounded-full h-2.5 w-2.5 bg-rose-600 border border-white dark:border-[#0c152e] shadow-sm" />
                      </span>
                    )}
                  </motion.div>

                  <div className="flex flex-col justify-center min-w-0">
                    {scrolled ? (
                      <span className="text-[0.6rem] sm:text-[0.75rem] md:text-[0.85rem] font-black tracking-wider whitespace-nowrap text-cyan-600 dark:text-cyan-400 uppercase">
                        {APP_TITLES.shortAppName[language]}
                      </span>
                    ) : (
                      <>
                        <span className="text-[0.4rem] sm:text-[0.48rem] md:text-[0.52rem] font-bold text-cyan-700 dark:text-cyan-500 uppercase tracking-tight leading-tight whitespace-nowrap">
                          {t('govOfNepal')}
                        </span>
                        <span className="text-[0.44rem] sm:text-[0.55rem] md:text-[0.62rem] font-bold text-cyan-700 dark:text-cyan-500 tracking-tight leading-tight whitespace-nowrap">
                          {t('ministryOfPhysical')}
                        </span>
                        <span className="text-[0.6rem] sm:text-[0.75rem] md:text-[0.88rem] font-black text-cyan-600 dark:text-cyan-400 tracking-tight leading-none whitespace-nowrap uppercase">
                          {t('deptOfRoads')}
                        </span>
                      </>
                    )}
                  </div>
                </>
              ) : (
                <motion.div 
                  initial={{ opacity: 0, x: -20 }}
                  animate={{ opacity: 1, x: 0 }}
                  className="flex-1 max-w-xl h-14 sm:h-16 flex items-center"
                >
                  <SearchDropdown 
                    indicators={indicators} 
                    searchQuery={searchQuery} 
                    onSearch={onSearch} 
                    sortType={sortType}
                    onSortChange={onSortChange}
                    onViewChange={onViewChange}
                    selectedCategory={selectedCategory}
                    onCategoryChange={onCategoryChange}
                    selectedOffice={selectedOffice}
                    onOfficeChange={onOfficeChange}
                    showMilestonesOnly={showMilestonesOnly}
                    onToggleMilestonesOnly={onToggleMilestonesOnly}
                    viewMode={viewMode}
                    viewOptions={viewOptions as any}
                    forceShowSearch={true}
                  />
                </motion.div>
              )}
            </div>

            {/* Right Controls */}
            <div className="flex items-center gap-1.5 sm:gap-2 shrink-0">
              {/* Syncing Status */}
              <AnimatePresence>
                {pendingWrites.length > 0 && isOnline && (
                  <motion.div
                    initial={{ opacity: 0, scale: 0.8 }}
                    animate={{ opacity: 1, scale: 1 }}
                    exit={{ opacity: 0, scale: 0.8 }}
                    className="flex items-center gap-1 bg-indigo-500 text-white px-1.5 sm:px-2.5 py-0.5 sm:py-1 rounded-full shadow-lg border border-indigo-400"
                  >
                    <CloudUpload size={10} className="animate-bounce sm:w-[12px] sm:h-[12px]" />
                    <span className="text-[0.55rem] sm:text-[0.625rem] font-extrabold tracking-tighter">
                      {pendingWrites.length}
                    </span>
                  </motion.div>
                )}
              </AnimatePresence>

              {/* Theme Toggle Button */}
              <motion.button
                whileHover={{ scale: 1.05 }}
                whileTap={{ scale: 0.95 }}
                onClick={toggleTheme}
                className={`px-2 sm:px-3 py-1 sm:py-2 rounded-xl transition-all flex items-center gap-2 shadow-sm ${
                  themePref === 'dark' 
                    ? 'bg-slate-900 border border-white/10 text-amber-400' 
                    : themePref === 'system'
                    ? 'bg-indigo-50 border border-indigo-200 text-indigo-700'
                    : 'bg-white border-2 border-slate-900 text-slate-900'
                }`}
                title={language === 'en' ? `Theme: ${themePref}` : `थिम: ${themePref}`}
              >
                {getThemeIcon()}
                <span className="text-[10px] font-black uppercase tracking-wider hidden xs:inline">{themePref}</span>
              </motion.button>

              {/* Language Toggle */}
              <motion.button
                whileHover={{ scale: 1.05 }}
                whileTap={{ scale: 0.95 }}
                onClick={() => {
                  triggerHaptic('light');
                  setLanguage(language === 'ne' ? 'en' : 'ne');
                }}
                className="p-1 sm:p-2 rounded-xl bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-800 text-slate-600 dark:text-indigo-400 shadow-sm transition-all flex items-center justify-center"
              >
                <Languages className="w-3 sm:w-4 h-3 sm:h-4" />
              </motion.button>

                {/* Search Button (Replaces Notifications) */}
              <div className="relative">
                <motion.button
                  whileHover={{ scale: 1.05 }}
                  whileTap={{ scale: 0.95 }}
                    onClick={() => {
                      triggerHaptic('light');
                      setIsSearchVisible(!isSearchVisible);
                    }}
                    className={`p-1 sm:p-2 rounded-xl border shadow-sm transition-all flex items-center justify-center relative ${
                      isSearchVisible
                        ? 'bg-rose-50 dark:bg-rose-950/40 border-rose-500 text-rose-600 dark:text-rose-400'
                        : 'bg-slate-50 dark:bg-slate-900 border-slate-200 dark:border-slate-800 text-slate-600 dark:text-indigo-400'
                    }`}
                    title={isSearchVisible ? (language === 'en' ? 'Close Search' : 'खोज बन्द गर्नुहोस्') : (language === 'en' ? 'Search Indicators' : 'सूचकहरू खोज्नुहोस्')}
                  >
                    {isSearchVisible ? <X size={16} /> : <Search size={16} />}
                  </motion.button>
              </div>

            </div>
          </div>

          <AnimatePresence mode="wait">
            {!scrolled && (
              <motion.div
                initial={{ opacity: 0, height: 0, marginTop: 0 }}
                animate={{ opacity: 1, height: 'auto', marginTop: 0 }}
                exit={{ opacity: 0, height: 0, marginTop: 0 }}
                transition={{ duration: 0.3 }}
                className="overflow-hidden pb-0.5"
              >
                <div className="flex flex-col md:flex-row md:items-end justify-between gap-1.5 md:gap-4 mt-0 h-[45px] sm:h-[60px]">
                  <div className="border-l-2 border-cyan-600 dark:border-cyan-400 pl-2 py-0.5">
                    <h1 className="text-[0.6rem] sm:text-[0.75rem] md:text-[0.88rem] font-black text-slate-800 dark:text-slate-100 tracking-tight uppercase leading-none">
                      {t('dorProgress')}
                    </h1>
                    <p className="block text-[8px] sm:text-[10px] text-slate-500 dark:text-slate-400 font-medium tracking-tight mt-0.5">
                      {t('splashSubtext')}
                    </p>
                  </div>

                  <div className="flex-1 w-full max-w-sm md:max-w-md self-end hidden md:block">
                    {viewMode !== 'dashboard' && viewMode !== 'institutional' && !isSearchVisible && (
                      <SearchDropdown 
                        indicators={indicators} 
                        searchQuery={searchQuery} 
                        onSearch={onSearch} 
                        sortType={sortType}
                        onSortChange={onSortChange}
                        onViewChange={onViewChange}
                        selectedCategory={selectedCategory}
                        onCategoryChange={onCategoryChange}
                        showMilestonesOnly={showMilestonesOnly}
                        onToggleMilestonesOnly={onToggleMilestonesOnly}
                        viewMode={viewMode}
                        viewOptions={viewOptions as any}
                        hideSearchInput={true}
                      />
                    )}
                  </div>
                </div>
              </motion.div>
            )}
          </AnimatePresence>
        </div>
      </div>
    </header>
  );
};

