                                : "#6366f1"
                          }
                          stopOpacity="0"
                        />
                      </linearGradient>
                    </defs>

                    {/* Gradient Area */}
                    {areaPath && (
                      <motion.path
                        animate={{ d: areaPath }}
                        transition={{ duration: 0.8, ease: "easeInOut" }}
                        fill={`url(#sparkline-grad-${indicator.id})`}
                        stroke="none"
                      />
                    )}

                    {/* Volatility Glow Underlay */}
                    {linePath && volatilityMetrics.isVolatile && (
                      <motion.path
                        initial={{ pathLength: 0, opacity: 0.15 }}
                        animate={{
                          pathLength: 1,
                          opacity: [0.15, 0.5, 0.15],
                          d: linePath,
                        }}
                        transition={{
                          pathLength: { duration: 1.1, ease: "easeOut" },
                          opacity: {
                            repeat: Infinity,
                            duration: 2,
                            ease: "easeInOut",
                          },
                          d: { duration: 0.8, ease: "easeInOut" },
                        }}
                        fill="none"
                        stroke={
                          isTrendUp
                            ? "#10b981"
                            : isTrendDown
                              ? "#f43f5e"
                              : "#6366f1"
                        }
                        strokeWidth="5"
                        strokeLinecap="round"
                        strokeLinejoin="round"
                        style={{
                          filter: `drop-shadow(0px 0px 4px ${isTrendUp ? "#10b981" : isTrendDown ? "#f43f5e" : "#6366f1"})`,
                        }}
                      />
                    )}

                    {/* Smooth Line Path */}
                    {linePath && (
                      <motion.path
                        initial={{ pathLength: 0 }}
                        animate={{ pathLength: 1, d: linePath }}
                        transition={{
                          pathLength: { duration: 1.1, ease: "easeOut" },
                          d: { duration: 0.8, ease: "easeInOut" },
                        }}
                        fill="none"
                        stroke={
                          isTrendUp
                            ? "#10b981"
                            : isTrendDown
                              ? "#f43f5e"
                              : "#6366f1"
                        }
                        strokeWidth="2"
                        strokeLinecap="round"
                        strokeLinejoin="round"
                      />
                    )}

                    {/* Anomaly Event Outlier Dots & Glow Halos */}
                    {svgPoints.map((p, idx) => {
                      const isAnomaly = anomalyIndices.includes(idx);
                      if (!isAnomaly) return null;

                      const isHovered = hoveredPointIdx === idx;

                      return (
                        <g
                          key={`anomaly-${idx}`}
                          className="pointer-events-none"
                        >
                          {/* Outer pulsing ring/halo for anomaly */}
                          <motion.circle
                            animate={{
                              cx: p.x,
                              cy: p.y,
                              scale: isHovered ? [1.1, 1.6, 1.1] : [1, 1.45, 1],
                              opacity: [0.6, 0.2, 0.6],
                            }}
                            r={isHovered ? "8" : "5.5"}
                            fill="none"
                            stroke="#f59e0b"
                            strokeWidth="1.5"
                            strokeOpacity="0.6"
                            transition={{
                              cx: {
                                type: "spring",
                                stiffness: 300,
                                damping: 25,
                              },
                              cy: {
                                type: "spring",
                                stiffness: 300,
                                damping: 25,
                              },
                              scale: {
                                repeat: Infinity,
                                duration: 1.8,
                                ease: "easeInOut",
                              },
                              opacity: {
                                repeat: Infinity,
                                duration: 1.8,
                                ease: "easeInOut",
                              },
                            }}
                          />
                          {/* Distinct core dot */}
                          {!isHovered && (
                            <motion.circle
                              animate={{ cx: p.x, cy: p.y }}
                              transition={{
                                type: "spring",
                                stiffness: 300,
                                damping: 25,
                              }}
                              r="2.5"
                              fill="#f59e0b"
                              stroke="#ffffff"
                              strokeWidth="1"
                            />
                          )}
                        </g>
                      );
                    })}

                    {/* Pulsing Dot at the latest point */}
                    {svgPoints.length > 0 && hoveredPointIdx === null && (
                      <motion.circle
                        animate={{
                          cx: svgPoints[svgPoints.length - 1].x,
                          cy: svgPoints[svgPoints.length - 1].y,
                        }}
                        transition={{
                          type: "spring",
                          stiffness: 300,
                          damping: 25,
                        }}
                        r="2.5"
                        fill={
                          anomalyIndices.includes(svgPoints.length - 1)
                            ? "#f59e0b"
                            : isTrendUp
                              ? "#10b981"
                              : isTrendDown
                                ? "#f43f5e"
                                : "#6366f1"
                        }
                      />
                    )}

                    {/* Active Highlight Dot */}
                    {hoveredPointIdx !== null && svgPoints[hoveredPointIdx] && (
                      <motion.circle
                        animate={{
                          cx: svgPoints[hoveredPointIdx].x,
                          cy: svgPoints[hoveredPointIdx].y,
