                        className="pointer-events-none"
                      />
                    )}

                    {/* Transparent Interactive Hover/Touch Hitboxes */}
                    {svgPoints.map((p, idx) => {
                      const colWidth = width / (svgPoints.length || 1);
                      const xStart = idx === 0 ? 0 : p.x - colWidth / 2;
                      const xWidth =
                        idx === 0
                          ? p.x + colWidth / 2
                          : idx === svgPoints.length - 1
                            ? width - xStart
                            : colWidth;
                      return (
                        <rect
                          key={idx}
                          x={xStart}
                          y={0}
                          width={xWidth}
                          height={height}
                          fill="transparent"
                          className="cursor-pointer"
                          onMouseEnter={() => {
                        setHoveredPointIdx(idx);
                        triggerHaptic('light');
                      }}
                          onMouseLeave={() => setHoveredPointIdx(null)}
                          onTouchStart={(e) => {
                            e.stopPropagation();
                            setHoveredPointIdx(idx);
                          }}
                          onTouchEnd={() => setHoveredPointIdx(null)}
                        />
                      );
                    })}
                  </svg>
                </motion.div>
              </div>
            )}

            {/* ANNUAL COMPLETION METER */}
            <div className="space-y-1 bg-slate-50/50 dark:bg-slate-800/30 p-2.5 rounded-xl border border-slate-100/50 dark:border-slate-800/50">
