                </div>
              </div>

              {/* Progress track */}
              <div className="flex items-center gap-2">
                <div className="w-full bg-slate-100 dark:bg-slate-950 h-1.5 rounded-full overflow-hidden shadow-inner ring-1 ring-slate-200/50 dark:ring-white/5">
