          </div>

          {/* METRICS TIMESTAMP AND AUTHOR FOOT NOTE */}
          {!actualIsCompact && indicator.updatedAt && (
            <div className="mt-3.5 text-[0.5625rem] text-slate-400 dark:text-slate-500 flex items-center justify-between border-t border-slate-50/55 dark:border-slate-800/50 pt-2">
              <span className="truncate max-w-[120px]">
                {t("by")}: {indicator.updatedBy || "SystemSync"}
              </span>
              <span>{new Date(indicator.updatedAt).toLocaleDateString()}</span>
            </div>
          )}
        </motion.div>
        </div>
      </motion.div>
    );
  },
);

