                      <ResponsiveContainer width="100%" height="100%">
                        <AreaChart data={chartData}>
                          <Area type="monotone" dataKey="progress" stroke="#6366f1" fill="#c7d2fe" strokeWidth={1} />
                        </AreaChart>
