              </div>
            </div>

            {/* On Track KPI Card */}
            <div className="bg-blue-50 dark:bg-blue-900/10 p-3 rounded-xl border border-blue-100 dark:border-blue-900/30 text-center flex flex-col justify-between items-center h-32">
              <div>
