                  <div className="space-y-1.5 text-xs font-bold text-slate-700 dark:text-slate-300">
                    <div className="flex items-center gap-2">
                      <div className="w-3.5 h-3.5 rounded-full bg-emerald-500 border border-white dark:border-slate-800 shadow" />
                      <span>{language === 'en' ? 'High Target (≥ 80%)' : 'उच्च प्रगतितर्फ (≥ ८०%)'}</span>
                    </div>
                    <div className="flex items-center gap-2">
                      <div className="w-3.5 h-3.5 rounded-full bg-amber-500 border border-white dark:border-slate-800 shadow" />
                      <span>{language === 'en' ? 'Medium Target (50%-79%)' : 'मध्यम प्रगति (५०%-७९%)'}</span>
                    </div>
                    <div className="flex items-center gap-2">
                      <div className="w-3.5 h-3.5 rounded-full bg-rose-500 border border-white dark:border-slate-800 shadow animate-pulse" />
                      <span>{language === 'en' ? 'Low Target (< 50%)' : 'न्यून प्रगति (< ५०%)'}</span>
                    </div>
                  </div>
                </div>

                <MapContainer 
                  center={[28.2096, 83.9856]} // Pokhara/Center of Nepal for better balanced zoom center
                  zoom={7} 
                  style={{ height: '100%', width: '100%', zIndex: 0 }}
                >
                  <TileLayer
                    attribution='&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors'
                    url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
                  />

                  {activeLayer === 'indicators' && indicators.map((indicator, index) => {
                    const pos = getCoordinates(indicator.id, index);
                    const target = indicator.annualTarget || 1;
                    const progress = indicator.annualProgress || 0;
                    const rate = Math.min(100, Math.round((progress / target) * 100));

                    return (
                      <Marker key={indicator.id} position={pos} icon={createIndicatorIcon(rate)}>
                        <Popup>
                          <div className="font-sans text-left max-w-xs p-1">
                            <div className="flex items-center gap-1.5 text-[10px] font-black text-indigo-500 uppercase tracking-widest mb-1.5">
                              <Sliders size={12} />
                              <span>{language === 'en' ? 'Road Indicator' : 'सडक विकास सूचक'}</span>
                            </div>
                            <h3 className="font-black text-sm text-slate-900 dark:text-white leading-snug mb-2">
                              {language === 'en' ? (indicator.nameEn || indicator.name) : indicator.name}
                            </h3>
                            <div className="text-[10px] text-slate-500 dark:text-slate-400 font-bold mb-3 flex items-center gap-1">
                              <Building2 size={10} className="text-slate-400" />
                              <span className="truncate max-w-[200px]">{indicator.office || (language === 'en' ? 'Department of Roads' : 'सडक विभाग')}</span>
                            </div>

                            <div className="bg-slate-50 dark:bg-slate-800/40 p-2.5 rounded-xl border border-slate-100 dark:border-slate-800 space-y-1.5">
                              <div className="flex justify-between items-center text-xs font-bold text-slate-700 dark:text-slate-300">
                                <span>{language === 'en' ? 'Completion' : 'उपलब्धि'}:</span>
                                <span className={`font-black ${rate >= 80 ? 'text-emerald-500' : rate >= 50 ? 'text-amber-500' : 'text-rose-500'}`}>
                                  {language === 'en' ? `${rate}%` : `${toNepaliNumerals(rate)}%`}
                                </span>
                              </div>
                              <div className="w-full bg-slate-200 dark:bg-slate-700 h-1.5 rounded-full overflow-hidden">
                                <div 
                                  className={`h-full rounded-full ${rate >= 80 ? 'bg-emerald-500' : rate >= 50 ? 'bg-amber-500' : 'bg-rose-500'}`}
                                  style={{ width: `${rate}%` }}
                                />
                              </div>

                              <div className="flex justify-between items-center text-[10px] pt-1 text-slate-500 dark:text-slate-400 font-mono">
                                <span>{language === 'en' ? 'Progress' : 'प्रगति'}: <b>{language === 'en' ? indicator.annualProgress : toNepaliNumerals(indicator.annualProgress)} {indicator.unit}</b></span>
                                <span>{language === 'en' ? 'Target' : 'लक्ष्य'}: <b>{language === 'en' ? indicator.annualTarget : toNepaliNumerals(indicator.annualTarget)} {indicator.unit}</b></span>
                              </div>
                            </div>
                          </div>
                        </Popup>
                      </Marker>
                    );
                  })}

                  {activeLayer === 'offices' && officePerformances.map((office) => {
                    return (
                      <Marker key={office.name} position={office.coordinates} icon={createOfficeIcon(office.averageProgress)}>
                        <Popup>
                          <div className="font-sans text-left max-w-sm p-1">
                            <div className="flex items-center gap-1.5 text-[10px] font-black text-indigo-500 uppercase tracking-widest mb-1.5">
                              <Building2 size={12} />
                              <span>{language === 'en' ? 'DoR Project Office' : 'सडक विभाग आयोजना कार्यालय'}</span>
                            </div>
                            <h3 className="font-black text-sm text-slate-900 dark:text-white leading-snug mb-2">
                              {office.name}
                            </h3>

                            {/* Progress overview */}
                            <div className="bg-slate-50 dark:bg-slate-800/40 p-2.5 rounded-xl border border-slate-100 dark:border-slate-800 space-y-1.5 mb-3">
                              <div className="flex justify-between items-center text-xs font-bold text-slate-700 dark:text-slate-300">
                                <span>{language === 'en' ? 'Average Progress' : 'औसत प्रगति'}:</span>
                                <span className={office.averageProgress >= 80 ? 'text-emerald-500 font-extrabold' : office.averageProgress >= 50 ? 'text-amber-500 font-extrabold' : 'text-rose-500 font-extrabold'}>
                                  {language === 'en' ? `${office.averageProgress}%` : `${toNepaliNumerals(office.averageProgress)}%`}
                                </span>
                              </div>
                              <div className="w-full bg-slate-200 dark:bg-slate-700 h-1.5 rounded-full overflow-hidden">
                                <div 
                                  className={`h-full rounded-full ${office.averageProgress >= 80 ? 'bg-emerald-500' : office.averageProgress >= 50 ? 'bg-amber-500' : 'bg-rose-500'}`}
                                  style={{ width: `${office.averageProgress}%` }}
                                />
                              </div>

                              <div className="flex justify-between items-center text-[10px] text-slate-500 dark:text-slate-400 font-medium">
                                <span>{language === 'en' ? 'Indicators Group' : 'सूचक समूह'}:</span>
                                <span className="font-mono">{language === 'en' ? `${office.indicators.length} Items` : `${toNepaliNumerals(office.indicators.length)} सूचकहरू`}</span>
                              </div>
                            </div>

                            {/* Counts */}
                            <div className="grid grid-cols-3 gap-2 text-center text-[10px] mb-3">
                              <div className="bg-emerald-50 dark:bg-emerald-950/20 text-emerald-700 dark:text-emerald-400 rounded-lg p-1.5 font-bold border border-emerald-100 dark:border-emerald-500/10">
                                <div className="font-black text-xs">{language === 'en' ? office.highCount : toNepaliNumerals(office.highCount)}</div>
                                <div>{language === 'en' ? 'High' : 'उच्च'}</div>
                              </div>
                              <div className="bg-amber-50 dark:bg-amber-950/20 text-amber-700 dark:text-amber-400 rounded-lg p-1.5 font-bold border border-amber-100 dark:border-amber-500/10">
                                <div className="font-black text-xs">{language === 'en' ? office.mediumCount : toNepaliNumerals(office.mediumCount)}</div>
                                <div>{language === 'en' ? 'Medium' : 'मध्यम'}</div>
                              </div>
                              <div className="bg-rose-50 dark:bg-rose-950/20 text-rose-700 dark:text-rose-400 rounded-lg p-1.5 font-bold border border-rose-100 dark:border-rose-500/10">
                                <div className="font-black text-xs">{language === 'en' ? office.lowCount : toNepaliNumerals(office.lowCount)}</div>
                                <div>{language === 'en' ? 'Low' : 'न्यून'}</div>
                              </div>
                            </div>

                            {/* Indicators List (Scrollable) */}
                            <div className="max-h-24 overflow-y-auto space-y-1.5 border-t border-slate-100 dark:border-slate-800 pt-2.5">
                              <div className="text-[9px] font-black uppercase text-slate-400 dark:text-slate-500 tracking-wider">
                                {language === 'en' ? 'Indicator Details' : 'सूचक विवरणहरू'}
                              </div>
                              {office.indicators.map((ind) => {
                                const indTarget = ind.annualTarget || 1;
                                const indProgress = ind.annualProgress || 0;
                                const rate = Math.min(100, Math.round((indProgress / indTarget) * 100));
                                return (
                                  <div key={ind.id} className="flex justify-between items-center gap-3 text-[10px] hover:bg-slate-100 dark:hover:bg-slate-800/50 p-1 rounded transition-colors">
                                    <span className="text-slate-700 dark:text-slate-300 font-bold truncate max-w-[160px]" title={language === 'en' ? ind.nameEn : ind.name}>
                                      {language === 'en' ? ind.nameEn : ind.name}
                                    </span>
                                    <span className={`font-mono font-black shrink-0 ${rate >= 80 ? 'text-emerald-500' : rate >= 50 ? 'text-amber-500' : 'text-rose-500'}`}>
                                      {language === 'en' ? `${rate}%` : `${toNepaliNumerals(rate)}%`}
                                    </span>
                                  </div>
                                );
                              })}
                            </div>
                          </div>
                        </Popup>
                      </Marker>
                    );
                  })}
                </MapContainer>
              </>
            )}
          </div>
        </motion.div>
      </div>
    </AnimatePresence>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { Indicator } from '../types';
import { 
  BarChart, 
  Bar, 
  LineChart, 
  Line, 
  AreaChart, 
  Area, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer, 
  Cell, 
  LabelList,
  ReferenceLine,
  ReferenceDot,
  Scatter
} from 'recharts';
import { BarChart3, LineChart as LineChartIcon, Activity, Sparkles, AlertCircle, Rocket, Trophy, Star, Pin } from 'lucide-react';
import { useLanguage } from '../context/LanguageContext';
import { HISTORICAL_DATA } from '../historicalData';
import { triggerHaptic } from '../utils/haptic';

interface ChartProps {
  indicators: Indicator[];
}

export const MetricsChart: React.FC<ChartProps> = ({ indicators }) => {
  const { language, t } = useLanguage();
  const [isVertical, setIsVertical] = useState(true);
  const [showAnnotations, setShowAnnotations] = useState(true);

  const [chartType, setChartType] = useState<'bar' | 'line' | 'area'>(() => {
    if (typeof window !== 'undefined') {
      const saved = localStorage.getItem('dor_chart_type_pref');
      if (saved === 'bar' || saved === 'line' || saved === 'area') {
        return saved;
      }
    }
    return 'bar';
  });

  useEffect(() => {
    localStorage.setItem('dor_chart_type_pref', chartType);
  }, [chartType]);

  const chartData = useMemo(() => {
    const lastSnapshot = HISTORICAL_DATA[HISTORICAL_DATA.length - 1];

    return indicators.map(ind => {
      const histInd = lastSnapshot?.indicators.find(h => h.id === ind.id || h.name === ind.name);
      const prevProgress = histInd ? histInd.annualProgress : 0;
      const prevTarget = histInd ? histInd.annualTarget : ind.annualTarget;
      const prevPercent = prevTarget > 0 ? Math.min(100, Math.round((prevProgress / prevTarget) * 100)) : 0;

      const currentPercent = ind.annualTarget > 0 ? Math.min(100, Math.round((ind.annualProgress / ind.annualTarget) * 100)) : 0;
      const delta = currentPercent - prevPercent;

      let annotation = null;
      if (currentPercent >= 100 && prevPercent < 100) {
        annotation = { type: 'milestone', label: '100%', icon: <Trophy size={10} className="text-amber-500" />, color: '#f59e0b', bg: '#fef3c7' };
      } else if (currentPercent >= 75 && prevPercent < 75) {
        annotation = { type: 'milestone', label: '75%', icon: <Star size={10} className="text-slate-400" />, color: '#94a3b8', bg: '#f1f5f9' };
      } else if (currentPercent >= 50 && prevPercent < 50) {
        annotation = { type: 'milestone', label: '50%', icon: <Pin size={10} className="text-indigo-500" />, color: '#6366f1', bg: '#e0e7ff' };
      } else if (delta >= 15) {
        annotation = { type: 'spike', label: `+${delta}%`, icon: <Rocket size={10} className="text-emerald-500" />, color: '#10b981', bg: '#ecfdf5' };
      } else if (delta < -2) {
        annotation = { type: 'dip', label: `${delta}%`, icon: <AlertCircle size={10} className="text-rose-500" />, color: '#f43f5e', bg: '#fff1f2' };
      }

      return {
        id: ind.id,
        name: (language === 'en' ? ind.nameEn : ind.name).split(' - ')[0].split('(')[0],
        fullName: language === 'en' ? ind.nameEn : ind.name,
        progress: ind.annualProgress,
        target: ind.annualTarget,
        baseline: ind.baseline,
        unit: ind.unit,
        percent: currentPercent,
        prevPercent,
        delta,
        annotation
      };
    }).sort((a, b) => b.percent - a.percent);
  }, [indicators, language]);

  const averagePercent = useMemo(() => {
    return Math.round(chartData.reduce((acc, d) => acc + d.percent, 0) / (chartData.length || 1));
  }, [chartData]);

  const annotationsList = useMemo(() => {
    return chartData.filter(d => d.annotation !== null).map(d => ({
      ...d,
      x: d.name,
      y: d.percent
    }));
  }, [chartData]);

  const CustomTooltip = ({ active, payload }: any) => {
    if (active && payload && payload.length) {
      const data = payload[0].payload;
      const baselineValue = typeof data.baseline === 'number' ? data.baseline : parseFloat(data.baseline);
      const hasValidBaseline = !isNaN(baselineValue) && baselineValue !== 0;
      const changeFromBaseline = hasValidBaseline 
        ? Math.round(((data.progress - baselineValue) / Math.abs(baselineValue)) * 100)
        : null;

      return (
        <div className="bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 p-4 rounded-2xl shadow-xl shadow-slate-200/50 dark:shadow-black/50 min-w-[240px] backdrop-blur-md">
          <p className="text-xs font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest mb-1">
            {t('performanceDetail')}
          </p>
          <h4 className="text-sm font-bold text-slate-800 dark:text-slate-100 mb-3 leading-tight">
            {data.fullName}
          </h4>

          <div className="space-y-2.5">
            <div className="flex items-center justify-between">
              <span className="text-[11px] font-medium text-slate-500 dark:text-slate-400">{t('annualProgress')}</span>
              <span className="text-xs font-bold text-indigo-600 dark:text-indigo-400">
                {data.progress} <span className="text-[10px] font-normal text-slate-400">{data.unit}</span>
              </span>
            </div>

            <div className="flex items-center justify-between">
              <span className="text-[11px] font-medium text-slate-500 dark:text-slate-400">{t('annualTarget')}</span>
              <span className="text-xs font-bold text-slate-700 dark:text-slate-200">
                {data.target} <span className="text-[10px] font-normal text-slate-400">{data.unit}</span>
              </span>
            </div>

            <div className="flex items-center justify-between">
              <span className="text-[11px] font-medium text-slate-500 dark:text-slate-400">{t('baseline')}</span>
              <span className="text-xs font-bold text-slate-700 dark:text-slate-200">
                {data.baseline} <span className="text-[10px] font-normal text-slate-400">{data.unit}</span>
              </span>
            </div>

            <div className="pt-2 border-t border-slate-100 dark:border-slate-800 flex items-center justify-between">
              <span className="text-[11px] font-bold text-slate-800 dark:text-slate-200">{t('completion')}</span>
              <div className="flex items-center gap-2">
                <div className="w-16 h-1.5 bg-slate-100 dark:bg-slate-800 rounded-full overflow-hidden">
                  <div 
                    className={`h-full rounded-full ${data.percent >= 100 ? 'bg-emerald-500' : 'bg-indigo-500'}`}
                    style={{ width: `${data.percent}%` }}
                  />
                </div>
                <span className={`text-[11px] font-black ${data.percent >= 100 ? 'text-emerald-600 dark:text-emerald-400' : 'text-indigo-600 dark:text-indigo-400'}`}>
                  {data.percent}%
                </span>
              </div>
            </div>

            {changeFromBaseline !== null && (
              <div className="flex items-center justify-between mt-1">
                <span className="text-[11px] font-medium text-slate-500 dark:text-slate-400">{t('vsBaseline')}</span>
                <span className={`text-[11px] font-bold px-1.5 py-0.5 rounded-md ${changeFromBaseline >= 0 ? 'bg-emerald-500/10 text-emerald-600 dark:text-emerald-400' : 'bg-rose-500/10 text-rose-600 dark:text-rose-400'}`}>
                  {changeFromBaseline >= 0 ? '+' : ''}{changeFromBaseline}%
                </span>
              </div>
            )}
          </div>
        </div>
      );
    }
    return null;
  };

  return (
    <div className="bg-white dark:bg-slate-900 rounded-3xl p-6 border border-slate-200 dark:border-slate-800 shadow-sm col-span-12" id="metrics-charts-panel">
      <div className="flex items-center justify-between border-b border-slate-100 dark:border-slate-800 pb-4 mb-6">
        <div className="flex items-center gap-3">
          <div className="p-2 bg-indigo-50 dark:bg-indigo-900/30 rounded-lg">
            <BarChart3 size={20} className="text-indigo-600 dark:text-indigo-400" />
          </div>
          <div>
            <h3 className="text-base font-bold text-slate-800 dark:text-slate-100 font-display">{t('overallPerformance')}</h3>
            <p className="text-[10px] text-slate-500 uppercase tracking-wider font-semibold">{t('overallProgress')}</p>
          </div>
        </div>
        <div className="flex items-center gap-2">
          <div className="flex bg-slate-100 dark:bg-slate-800 rounded-lg p-1">
            <button
              onClick={() => setChartType('bar')}
              className={`p-1.5 rounded-md transition-all ${chartType === 'bar' ? 'bg-white dark:bg-slate-700 shadow-sm text-indigo-600 dark:text-indigo-400' : 'text-slate-500 hover:text-slate-700 dark:hover:text-slate-300'}`}
              title="Bar Chart"
            >
              <BarChart3 size={16} />
            </button>
            <button
              onClick={() => setChartType('line')}
              className={`p-1.5 rounded-md transition-all ${chartType === 'line' ? 'bg-white dark:bg-slate-700 shadow-sm text-indigo-600 dark:text-indigo-400' : 'text-slate-500 hover:text-slate-700 dark:hover:text-slate-300'}`}
              title="Line Chart"
            >
              <LineChartIcon size={16} />
            </button>
            <button
              onClick={() => setChartType('area')}
              className={`p-1.5 rounded-md transition-all ${chartType === 'area' ? 'bg-white dark:bg-slate-700 shadow-sm text-indigo-600 dark:text-indigo-400' : 'text-slate-500 hover:text-slate-700 dark:hover:text-slate-300'}`}
              title="Area Chart"
            >
              <Activity size={16} />
            </button>
          </div>
          <button
            onClick={() => setIsVertical(!isVertical)}
            className="text-xs font-bold text-indigo-600 dark:text-indigo-400 px-3 py-1 bg-indigo-50 dark:bg-indigo-900/50 rounded-lg h-[32px] flex items-center"
          >
            {isVertical ? t('rotateHorizontal') : t('rotateVertical')}
          </button>
          <button
            onClick={() => setShowAnnotations(!showAnnotations)}
            className={`p-1.5 rounded-md transition-all h-[32px] w-[32px] flex items-center justify-center ${showAnnotations ? 'bg-indigo-600 text-white shadow-sm' : 'bg-slate-100 dark:bg-slate-800 text-slate-500'}`}
            title={language === 'en' ? 'Toggle Annotations' : 'एनोटेसनहरू टगल गर्नुहोस्'}
          >
            <Sparkles size={16} />
          </button>
        </div>
      </div>

      <div className="h-[600px] w-full overflow-y-auto custom-scrollbar">
        <ResponsiveContainer width="100%" height={isVertical ? chartData.length * 50 : 500}>
          {chartType === 'bar' && (
            <BarChart
              data={chartData}
              layout={isVertical ? "vertical" : "horizontal"}
              margin={{ top: 5, right: 30, left: isVertical ? 100 : 0, bottom: 5 }}
            >
              <CartesianGrid strokeDasharray="3 3" horizontal={isVertical} vertical={!isVertical} />
              {isVertical ? (
                <>
                  <XAxis type="number" domain={[0, 100]} unit="%" />
                  <YAxis type="category" dataKey="name" width={90} tick={{ fontSize: 10 }} />
                </>
              ) : (
                <>
                  <XAxis type="category" dataKey="name" tick={{ fontSize: 10 }} />
                  <YAxis type="number" domain={[0, 100]} unit="%" />
                </>
              )}
              <Tooltip content={<CustomTooltip />} />
              <ReferenceLine 
