import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'motion/react';
import { WifiOff, AlertCircle } from 'lucide-react';
import { useLanguage } from '../context/LanguageContext';

export const OfflineStatusBar: React.FC = () => {
  const { language } = useLanguage();
  const [isOffline, setIsOffline] = useState(!navigator.onLine);

  useEffect(() => {
    const handleOnline = () => setIsOffline(false);
    const handleOffline = () => setIsOffline(true);

    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);

    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  return (
    <AnimatePresence>
      {isOffline && (
        <motion.div
          initial={{ height: 0, opacity: 0 }}
          animate={{ height: 'auto', opacity: 1 }}
          exit={{ height: 0, opacity: 0 }}
          className="bg-amber-500/10 dark:bg-amber-500/5 backdrop-blur-md border-b border-amber-500/20 overflow-hidden"
        >
          <div className="max-w-7xl mx-auto px-4 py-1.5 flex items-center justify-center gap-2">
            <div className="flex items-center gap-1.5">
              <WifiOff size={12} className="text-amber-600 dark:text-amber-400 animate-pulse" />
              <span className="text-[10px] font-black uppercase tracking-widest text-amber-700 dark:text-amber-400">
                {language === 'en' ? 'Working Offline' : 'अफलाइन काम गर्दै'}
              </span>
            </div>
            <span className="w-1 h-1 rounded-full bg-amber-400 dark:bg-amber-500/40" />
            <p className="text-[9px] font-bold text-amber-600/80 dark:text-amber-400/60 uppercase tracking-tight">
              {language === 'en' ? 'Changes will sync when reconnected' : 'पुनः जडान भएपछि परिवर्तनहरू सिंक हुनेछन्'}
            </p>
          </div>
        </motion.div>
      )}
    </AnimatePresence>
  );
};

