const toNepaliNumerals = (numStr: string | number): string => {
  const nepaliDigits = ['०', '१', '२', '३', '४', '५', '६', '७', '८', '९'];
  return numStr
    .toString()
    .split('')
    .map((char) => {
      const index = parseInt(char, 10);
      return !isNaN(index) ? nepaliDigits[index] : char;
    })
    .join('');
};

