import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'motion/react';
import { Download, X, Smartphone, Globe, Share } from 'lucide-react';
import { useLanguage } from '../context/LanguageContext';

export const PWAInstallBanner: React.FC = () => {
  const { language } = useLanguage();
  const [showBanner, setShowBanner] = useState(false);
  const [isOffline, setIsOffline] = useState(!navigator.onLine);
  const [deferredPrompt, setDeferredPrompt] = useState<any>(null);

  useEffect(() => {
    const handleOnline = () => setIsOffline(false);
    const handleOffline = () => setIsOffline(true);
    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);

    const handleBeforeInstallPrompt = (e: any) => {
      // Prevent the mini-infobar from appearing on mobile
      e.preventDefault();
      // Stash the event so it can be triggered later.
      setDeferredPrompt(e);
      checkVisibility();
    };
    window.addEventListener('beforeinstallprompt', handleBeforeInstallPrompt);

    const checkVisibility = () => {
      const isStandalone = window.matchMedia('(display-mode: standalone)').matches || (window.navigator as any).standalone === true;
      const isMobile = /Android|webOS|iPhone|iPad|iPod|BlackBerry|IEMobile|Opera Mini/i.test(navigator.userAgent);

      // Show if mobile and not installed, OR if offline (regardless of platform, though designed for mobile)
      if (isMobile && !isStandalone) {
        setShowBanner(true);
      } else if (isOffline) {
        setShowBanner(true);
      }
    };

    // Initial check
    checkVisibility();

    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
      window.removeEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
    };
  }, [isOffline]);

  const handleInstallClick = async () => {
    if (deferredPrompt) {
      // Show the install prompt
      deferredPrompt.prompt();
      // Wait for the user to respond to the prompt
      const { outcome } = await deferredPrompt.userChoice;
      if (outcome === 'accepted') {
        console.log('User accepted the install prompt');
        setShowBanner(false);
      } else {
        console.log('User dismissed the install prompt');
      }
      // We've used the prompt, and can't use it again, throw it away
      setDeferredPrompt(null);
    } else {
      // Manual instructions for iOS or other browsers that don't support beforeinstallprompt
      const isIOS = /iPad|iPhone|iPod/.test(navigator.userAgent) && !(window as any).MSStream;
      if (isIOS) {
        alert(language === 'en' 
          ? "To install: Tap the Share button in Safari and select 'Add to Home Screen'."
          : "इन्स्टल गर्नका लागि: सफारीमा सेयर बटनमा ट्याप गर्नुहोस् र 'Add to Home Screen' चयन गर्नुहोस्।");
      } else {
        alert(language === 'en'
          ? "Check your browser menu for 'Install App' or 'Add to Home Screen'."
          : "तपाईंको ब्राउजर मेनुमा 'Install App' वा 'Add to Home Screen' खोज्नुहोस्।");
      }
    }
  };

  if (!showBanner) return null;

  return (
    <AnimatePresence>
      <motion.div
        initial={{ y: 100, opacity: 0 }}
        animate={{ y: 0, opacity: 1 }}
        exit={{ y: 100, opacity: 0 }}
        className="fixed bottom-6 left-4 right-4 z-[200] md:hidden"
      >
        <div className="bg-indigo-600 dark:bg-indigo-500 rounded-2xl p-4 shadow-2xl shadow-indigo-500/30 border border-indigo-400 flex items-center gap-4">
          <div className="w-12 h-12 bg-white/20 rounded-xl flex items-center justify-center shrink-0">
            {isOffline ? (
              <Globe className="text-white w-6 h-6 animate-pulse" />
            ) : (
              <Smartphone className="text-white w-6 h-6" />
            )}
          </div>
          <div className="flex-1 min-w-0">
            <h3 className="text-white font-bold text-sm leading-tight">
              {isOffline 
                ? (language === 'en' ? "You're Offline" : "तपाईं अफलाइन हुनुहुन्छ")
                : (language === 'en' ? "Install IDPTS App" : "IDPTS एप इन्स्टल गर्नुहोस्")}
            </h3>
            <p className="text-indigo-100 text-[10px] font-medium leading-snug mt-0.5">
              {isOffline 
                ? (language === 'en' ? "Access limited data. Install for better offline support." : "डाटा सीमित छ। राम्रो अफलाइन सपोर्टको लागि इन्स्टल गर्नुहोस्।")
                : (language === 'en' ? "Get a faster, more reliable experience on your home screen." : "राम्रो अनुभवको लागि होम स्क्रिनमा थप्नुहोस्।")}
            </p>
          </div>
          <div className="flex items-center gap-2">
            <button
              onClick={handleInstallClick}
              className="px-3 py-1.5 bg-white text-indigo-600 text-[11px] font-black uppercase tracking-tighter rounded-lg shadow-sm hover:bg-indigo-50 active:scale-95 transition-all whitespace-nowrap"
            >
              {isOffline ? (language === 'en' ? "Setup" : "सेटअप") : (language === 'en' ? "Install" : "इन्स्टल")}
            </button>
            <button
              onClick={() => setShowBanner(false)}
              className="p-1.5 text-white/60 hover:text-white transition-colors"
            >
              <X size={18} />
            </button>
          </div>
        </div>
      </motion.div>
    </AnimatePresence>
  );
};

import React, { useEffect, useRef } from 'react';
import * as d3 from 'd3';
import { Indicator } from '../types';
import { useLanguage } from '../context/LanguageContext';
import { normalizeCategory } from '../utils/category';

interface CorrelationProps {
  indicators: Indicator[];
  updatesHistory: any[];
}

export const PerformanceCorrelationHeatmap: React.FC<CorrelationProps> = ({ indicators, updatesHistory }) => {
  const svgRef = useRef<SVGSVGElement>(null);
  const { language } = useLanguage();

  useEffect(() => {
    if (!updatesHistory || updatesHistory.length === 0 || !svgRef.current) return;

    // 1. Prepare Data: Calculate office averages per history entry
    const offices = Array.from(new Set(indicators.map(i => i.office || 'Unassigned'))).sort() as string[];

    const timeSeries = updatesHistory.map(entry => {
        const snapshotIndicators = (entry.indicators || []) as Indicator[];
        const officeProgress: Record<string, number[]> = {};
        offices.forEach(o => {
            officeProgress[o] = [];
        });

        snapshotIndicators.forEach((ind: Indicator) => {
            const office = ind.office || 'Unassigned';
            if (officeProgress[office]) {
                const progress = ind.annualTarget > 0 ? (ind.annualProgress / ind.annualTarget) * 100 : 0;
                officeProgress[office].push(progress);
            }
        });

        const averages: Record<string, number> = {};
        offices.forEach(o => {
            const values = officeProgress[o];
            averages[o] = values.length > 0 ? values.reduce((a, b) => a + b, 0) / values.length : 0;
        });
        return averages;
    });

    // 2. Compute correlation matrix (simplified Pearson)
    const correlationMatrix: { office1: string, office2: string, correlation: number }[] = [];
    for (let i = 0; i < offices.length; i++) {
        for (let j = 0; j < offices.length; j++) {
            const o1 = offices[i] as string;
            const o2 = offices[j] as string;

            const vals1 = timeSeries.map(ts => ts[o1]);
            const vals2 = timeSeries.map(ts => ts[o2]);

            const mean1 = vals1.reduce((a, b) => a + b, 0) / vals1.length;
            const mean2 = vals2.reduce((a, b) => a + b, 0) / vals2.length;

            const num = vals1.reduce((acc, v, idx) => acc + (v - mean1) * (vals2[idx] - mean2), 0);
            const den = Math.sqrt(vals1.reduce((acc, v) => acc + (v - mean1) ** 2, 0) * vals2.reduce((acc, v) => acc + (v - mean2) ** 2, 0));

            correlationMatrix.push({
                office1: o1,
                office2: o2,
                correlation: den === 0 ? 0 : num / den
            });
        }
    }

    // 3. Render Heatmap with D3
    const svg = d3.select(svgRef.current);
    svg.selectAll("*").remove();

    const margin = { top: 60, right: 20, bottom: 60, left: 100 };
    const width = 450 - margin.left - margin.right;
    const height = 400 - margin.top - margin.bottom;

    const x = d3.scaleBand().range([0, width]).domain(offices).padding(0.05);
    const y = d3.scaleBand().range([height, 0]).domain(offices).padding(0.05);
    const color = d3.scaleSequential(d3.interpolateRdBu).domain([-1, 1]);

    const g = svg.append("g").attr("transform", `translate(${margin.left},${margin.top})`);

    g.selectAll("rect")
        .data(correlationMatrix)
        .enter().append("rect")
        .attr("x", d => x(d.office1)!)
        .attr("y", d => y(d.office2)!)
        .attr("width", x.bandwidth())
        .attr("height", y.bandwidth())
        .style("fill", d => color(d.correlation))
        .append("title")
        .text(d => `${d.office1} vs ${d.office2}: ${d.correlation.toFixed(2)}`);

    g.append("g").call(d3.axisTop(x)).selectAll("text").attr("transform", "rotate(-45)").style("text-anchor", "start").style("font-size", "8px");
    g.append("g").call(d3.axisLeft(y)).style("font-size", "8px");

  }, [indicators, updatesHistory, language]);

  return (
    <div className="bg-white dark:bg-slate-900 rounded-3xl p-6 border border-slate-200 dark:border-slate-800 shadow-sm col-span-12 lg:col-span-6">
        <h3 className="text-base font-bold text-slate-800 dark:text-slate-100 font-display mb-4">
            {language === 'en' ? 'Performance Correlation' : 'कार्यसम्पादन सम्बन्ध'}
        </h3>
        <div className="w-full h-[400px] overflow-hidden">
            <svg ref={svgRef} width="100%" height="100%" viewBox="0 0 450 400" />
        </div>
    </div>
  );
};

