import React, { useEffect, useState } from 'react';
import { motion } from 'motion/react';
import { useLanguage } from '../context/LanguageContext';

export const SplashScreen = ({ isLoaded }: { isLoaded: boolean }) => {
  const [progress, setProgress] = useState(0);
  const { t } = useLanguage();

  useEffect(() => {
    if (!isLoaded) {
      const interval = setInterval(() => {
        setProgress(prev => (prev < 90 ? prev + 1 : prev));
      }, 30);
      return () => clearInterval(interval);
    } else {
      setProgress(100);
    }
  }, [isLoaded]);

  return (
    <motion.div
      initial={{ opacity: 1 }}
      animate={{ opacity: isLoaded ? 0 : 1 }}
      className="fixed inset-0 z-[9999] flex flex-col items-center justify-center bg-white dark:bg-[#020617]"
      style={{ pointerEvents: isLoaded ? 'none' : 'auto' }}
    >
      {/* App Purpose at Center */}
      <div className="flex-1 flex flex-col items-center justify-center max-w-2xl px-6 text-center">
        <motion.div
          initial={{ opacity: 0, scale: 0.95 }}
          animate={{ opacity: 1, scale: 1 }}
          transition={{ duration: 0.8, ease: "easeOut" }}
          className="space-y-6"
        >
          <div className="flex flex-col items-center">
            <img 
              src="/GovtLogo.svg" 
              alt="Government of Nepal Logo" 
              className="w-20 h-20 sm:w-24 sm:h-24 object-contain mb-5 filter drop-shadow-md"
              referrerPolicy="no-referrer"
            />
            <div className="w-12 h-1 bg-[#0099DA] mb-6 rounded-full" />
            <h1 className="text-xl md:text-2xl font-black text-slate-900 dark:text-white tracking-tighter leading-tight uppercase max-w-lg mx-auto">
              {t('splashTitle')}
            </h1>
            <p className="text-slate-500 dark:text-slate-400 font-sans mt-3 text-[8px] sm:text-[9px] font-bold uppercase tracking-[0.2em] leading-relaxed max-w-sm mx-auto">
              {t('splashSubtext')}
