              className="h-full bg-[#0099DA]"
              initial={{ width: 0 }}
              animate={{ width: `${progress}%` }}
              transition={{ ease: "linear" }}
            />
          </div>
        </motion.div>
      </div>

      {/* Branding at Bottom Center */}
      <div className="pb-12 text-center px-6">
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.2, duration: 0.8 }}
          className="flex flex-col items-center"
        >
          <div className="mb-3">
            <img 
              src="/GovtLogo.svg" 
              alt="Government of Nepal Logo" 
              className="w-12 h-12 object-contain mx-auto filter drop-shadow-sm"
              referrerPolicy="no-referrer"
            />
          </div>
          <p className="text-[7px] sm:text-[8px] font-bold text-[#0099DA] dark:text-[#38bdf8]/80 tracking-[0.2em] mb-0.5">{t('govOfNepal')}</p>
          <p className="text-[7.5px] sm:text-[8.5px] font-bold text-[#0099DA] dark:text-[#38bdf8]/80 tracking-widest mb-0.5">{t('ministryOfPhysical')}</p>
          <p className="text-[9px] sm:text-[10px] font-extrabold text-[#0099DA] dark:text-[#38bdf8]/80 tracking-tight">{t('deptOfRoads')}</p>

          <div className="mt-4 opacity-30">
             <p className="text-[6px] text-[#0099DA] dark:text-slate-500 font-bold uppercase tracking-[0.4em]">
              SYSTEM VERSION 2.4.0
            </p>
          </div>
        </motion.div>
