};

import React, { useState, useEffect } from 'react';
import { motion } from 'motion/react';
import { useLanguage } from '../context/LanguageContext';

interface StartupScreenProps {
  onComplete: () => void;
}

export function StartupScreen({ onComplete }: StartupScreenProps) {
  const [progress, setProgress] = useState(0);
  const { t } = useLanguage();

  useEffect(() => {
    const interval = setInterval(() => {
      setProgress((prev) => {
        if (prev >= 100) {
          clearInterval(interval);
          return 100;
        }
        return prev + 1;
      });
    }, 30);

    return () => clearInterval(interval);
  }, []);

  useEffect(() => {
    let timeout: any;
    if (progress >= 100) {
      timeout = setTimeout(() => {
        onComplete();
      }, 1000);
    }
    return () => {
      if (timeout) clearTimeout(timeout);
    };
  }, [progress, onComplete]);

  return (
    <div className="fixed inset-0 z-[9999] bg-white dark:bg-[#020617] flex flex-col items-center justify-center p-8 font-sans">

      {/* Branding at Top */}
      <div className="absolute top-16 left-0 right-0 text-center px-6">
        <motion.div
          initial={{ opacity: 0, y: -20 }}
          animate={{ opacity: 1, y: 0 }}
          className="flex flex-col items-center"
        >
          <div className="mb-6">
            <img 
              src="/GovtLogo.svg" 
              alt="Government of Nepal Logo" 
              className="w-24 h-24 sm:w-28 sm:h-28 object-contain mx-auto filter drop-shadow-md"
              referrerPolicy="no-referrer"
            />
          </div>
          <p className="text-[10px] sm:text-[12px] font-bold text-[#0099DA] dark:text-[#38bdf8] tracking-widest mb-1.5">{t('govOfNepal')}</p>
          <p className="text-[11px] sm:text-[14px] font-bold text-[#0099DA] dark:text-[#38bdf8] tracking-tight mb-1.5">{t('ministryOfPhysical')}</p>
          <p className="text-[16px] sm:text-[22px] font-black text-[#0099DA] dark:text-[#38bdf8] tracking-tight">{t('deptOfRoads')}</p>
        </motion.div>
      </div>

      {/* Purpose at Center */}
      <div className="flex-1 flex flex-col items-center justify-center mt-32">
        <motion.div
          initial={{ opacity: 0, scale: 0.95 }}
          animate={{ opacity: 1, scale: 1 }}
          className="text-center"
        >
          <div className="w-20 h-1.5 bg-[#0099DA] mb-8 mx-auto rounded-full" />
          <h1 className="text-3xl sm:text-4xl font-black text-slate-900 dark:text-white tracking-tighter mb-4 max-w-sm">
            {t('splashTitle')}
          </h1>
          <p className="text-[10px] text-slate-500 dark:text-slate-400 font-bold tracking-widest uppercase">
            {t('splashSubtext')}
          </p>
        </motion.div>
      </div>

      {/* Progress Section */}
      <div className="w-full max-w-xs mb-20">
        <div className="w-full h-1 bg-slate-100 dark:bg-slate-800 rounded-full overflow-hidden">
           <motion.div 
              className="h-full bg-[#0099DA]"
              style={{ width: `${progress}%` }}
           />
        </div>
        <p className="text-[10px] font-bold text-slate-400 mt-4 text-center uppercase tracking-[0.3em]">
          {progress}% Initializing
        </p>
      </div>
    </div>
  );
}

