import React, { useState, useEffect, useCallback } from 'react';
import { motion, AnimatePresence } from 'motion/react';
import { 
  X, Info, Calculator, Building2, Database, RefreshCw, ExternalLink, 
  HelpCircle, CheckCircle, Scale, ChevronRight, ChevronLeft, Navigation, 
  Layers, Printer, Compass, MousePointerClick, Trash2, HardDrive, 
  Settings2, Smartphone, Sparkles, Clock, LayoutGrid, Target,
  Search, Activity, Mic, Volume2, Filter, ArrowRight, CornerDownRight
} from 'lucide-react';
import { useLanguage } from '../context/LanguageContext';
import { getHapticIntensity, setHapticIntensity, triggerHaptic } from '../utils/haptic';
import { Indicator } from '../types';
import { DOR_OFFICES_LIST } from '../data';

interface SystemHelpModalProps {
  isOpen: boolean;
  onClose: () => void;
  indicators: Indicator[];
  offices: { name: string; updated: string }[];
  onSync?: () => Promise<void>;
  isSyncing?: boolean;
  defaultTab?: 'tour' | 'logic' | 'offices' | 'sync' | 'settings' | 'voice';
  isAdmin?: boolean;
  lastUpdateDate?: string;
  pendingWritesCount?: number;
  isOnline?: boolean;
}

const VOICE_NAVIGATION_COMMANDS = [
  { en: 'Navigate to Table View', np: 'तालिका दृश्यमा जानुहोस्', keywordEn: 'Table View', keywordNp: 'टेबल / तालिका' },
  { en: 'Navigate to Card View', np: 'कार्ड दृश्यमा जानुहोस्', keywordEn: 'Card View', keywordNp: 'कार्ड' },
  { en: 'Navigate to Chart View', np: 'चार्ट दृश्यमा जानुहोस्', keywordEn: 'Chart View', keywordNp: 'चार्ट' },
  { en: 'Navigate to Heatmap View', np: 'हिटम्याप दृश्यमा जानुहोस्', keywordEn: 'हिटम्याप दृश्य', keywordNp: 'हिटम्याप' },
  { en: 'Navigate to Dashboard View', np: 'ड्यासबोर्डमा जानुहोस्', keywordEn: 'Dashboard View', keywordNp: 'ड्यासबोर्ड' },
];

const VOICE_FILTER_COMMANDS = [
  { en: 'Show Infrastructure Creation', np: 'पूर्वाधार सूचक देखाउनुहोस्', keywordEn: 'Infrastructure', keywordNp: 'पूर्वाधार / भौतिक' },
  { en: 'Show Road Maintenance', np: 'मर्मतसम्भार सूचक देखाउनुहोस्', keywordEn: 'Maintenance', keywordNp: 'मर्मत / सडक' },
  { en: 'Show Employment Creation', np: 'रोजगारी सिर्जना देखाउनुहोस्', keywordEn: 'Employment', keywordNp: 'रोजगार / रोजगारी' },
  { en: 'Show Budget Indicators', np: 'बजेट सूचकहरू देखाउनुहोस्', keywordEn: 'Budget', keywordNp: 'बजेट' },
  { en: 'Show Governance Indicators', np: 'सुशासन सूचक देखाउनुहोस्', keywordEn: 'Governance', keywordNp: 'सुशासन' },
  { en: 'Show All Indicators', np: 'सबै सूचकहरू देखाउनुहोस्', keywordEn: 'Show All / Clear', keywordNp: 'सबै' },
];

export const SystemHelpModal: React.FC<SystemHelpModalProps> = ({
  isOpen,
  onClose,
  indicators = [],
  offices = [],
  onSync,
  isSyncing = false,
  defaultTab = 'tour',
  isAdmin = false,
  lastUpdateDate = 'N/A',
  pendingWritesCount = 0,
  isOnline = true
}) => {
  const { language, t } = useLanguage();
  const [activeTab, setActiveTab] = useState<'tour' | 'logic' | 'offices' | 'indicators' | 'sync' | 'settings' | 'voice'>(defaultTab);
  const [step, setStep] = useState(0);
  const [searchQuery, setSearchQuery] = useState('');
  const [storageInfo, setStorageInfo] = useState({ size: '0 KB', totalBytes: 0, timestamp: 'N/A' });
  const [relativeTime, setRelativeTime] = useState('N/A');
  const [hapticPref, setHapticPref] = useState<'light' | 'medium' | 'heavy' | 'off'>('medium');

  // Sync tab selection with defaultTab when the modal opens
  useEffect(() => {
    if (isOpen) {
      setActiveTab(defaultTab);
      setStep(0);
      setSearchQuery('');
    }
  }, [isOpen, defaultTab]);

  // Initialize haptic preference on mount
  useEffect(() => {
    setHapticPref(getHapticIntensity());
  }, []);

  const handleHapticChange = (intensity: 'light' | 'medium' | 'heavy' | 'off') => {
    setHapticPref(intensity);
    setHapticIntensity(intensity);
    if (intensity !== 'off') {
      triggerHaptic('success');
    }
  };

  const calculateStorage = useCallback(() => {
    if (typeof window === 'undefined') return;
    try {
      const indStr = localStorage.getItem('dor_indicators_cache') || '';
      const metaStr = localStorage.getItem('dor_metadata_cache') || '';
      const totalBytes = indStr.length + metaStr.length;
      const kb = totalBytes / 1024;

      let lastSync = localStorage.getItem('dor_last_sync_timestamp');
      if (!lastSync) {
        const now = new Date();
        now.setMinutes(now.getMinutes() - 12);
        lastSync = now.toISOString();
        localStorage.setItem('dor_last_sync_timestamp', lastSync);
      }

      setStorageInfo({
        size: `${kb.toFixed(2)} KB`,
        totalBytes,
        timestamp: lastSync
      });
    } catch (e) {
      // Failed to calculate storage silently
    }
  }, []);

  const getRelativeTimeString = useCallback((isoString: string | null) => {
    if (!isoString || isoString === 'N/A') return language === 'en' ? 'Never' : 'कहिल्यै होइन';
    try {
      const past = new Date(isoString);
      const now = new Date();
      const diffMs = now.getTime() - past.getTime();
      const diffSec = Math.floor(diffMs / 1000);
      const diffMin = Math.floor(diffSec / 60);
      const diffHr = Math.floor(diffMin / 60);

      if (diffSec < 15) {
        return language === 'en' ? 'Just now' : 'भर्खरै';
      }
      if (diffSec < 60) {
        return language === 'en' ? `${diffSec}s ago` : `${diffSec} सेकेन्ड अघि`;
      }
      if (diffMin < 60) {
        return language === 'en' ? `${diffMin}m ago` : `${diffMin} मिनेट अघि`;
      }
      if (diffHr < 24) {
        return language === 'en' ? `${diffHr}h ago` : `${diffHr} घण्टा अघि`;
      }

      return past.toLocaleString(language === 'ne' ? 'ne-NP' : 'en-US', {
        month: 'short',
        day: 'numeric',
        hour: '2-digit',
        minute: '2-digit'
      });
    } catch (e) {
      return 'N/A';
    }
  }, [language]);

  const getAbsoluteTimeString = (isoString: string | null) => {
    if (!isoString || isoString === 'N/A') return 'N/A';
    try {
      const date = new Date(isoString);
      return date.toLocaleString(language === 'ne' ? 'ne-NP' : 'en-US', {
        year: 'numeric',
        month: 'long',
        day: 'numeric',
        hour: '2-digit',
        minute: '2-digit',
        second: '2-digit'
      });
    } catch (e) {
      return 'N/A';
    }
  };

  const handleClearCache = async () => {
    if (typeof window === 'undefined') return;
    try {
      localStorage.removeItem('dor_indicators_cache');
      localStorage.removeItem('dor_metadata_cache');
      localStorage.removeItem('dor_last_sync_timestamp');

      calculateStorage();

      if (onSync) {
        await onSync();
      }
    } catch (e) {
      // Failed to clear cache silently
    }
  };

  // Recalculate storage on load & when isSyncing finishes
  useEffect(() => {
    if (!isOpen) return;
    // Call asynchronously to avoid synchronous setState warnings during effect phase
    Promise.resolve().then(() => {
      calculateStorage();
    });
    const interval = setInterval(calculateStorage, 5000);
    return () => clearInterval(interval);
  }, [isOpen, isSyncing, calculateStorage]);

  // Handle live updating of relative timestamp strings
  useEffect(() => {
    if (!isOpen || !storageInfo.timestamp || storageInfo.timestamp === 'N/A') return;
    const updateRelative = () => {
      setRelativeTime(getRelativeTimeString(storageInfo.timestamp));
    };
    updateRelative();
    const interval = setInterval(updateRelative, 5000);
    return () => clearInterval(interval);
  }, [isOpen, storageInfo.timestamp, language, getRelativeTimeString]);

  // Auto-scroll to elements when steps change
  useEffect(() => {
    if (!isOpen) return;

    if (step === 3) {
      const el = document.getElementById('btn-print') || document.getElementById('app-footer');
      if (el) {
        el.scrollIntoView({ behavior: 'smooth', block: 'center' });
      }
    } else if (step === 1) {
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  }, [step, isOpen]);

  if (!isOpen) return null;

  const totalSteps = 4; // Step 0 (Welcome), Step 1 (Drawer), Step 2 (Switcher), Step 3 (Report)

  const handleNext = () => {
    if (step < totalSteps - 1) {
      setStep(prev => prev + 1);
    } else {
      onClose();
    }
  };

  const handlePrev = () => {
    if (step > 0) {
      setStep(prev => prev - 1);
    }
  };

  // Math variables
  const weightedIndicators = indicators.filter(ind => (ind.weight || 0) > 0);
  const totalWeightSum = indicators.reduce((acc, ind) => acc + (ind.weight || 0), 0);

  // Calculate average using the exact formula
  const totalWeightedProgress = indicators.reduce((acc, ind) => {
    const weight = ind.weight || 0;
    const progress = ind.annualTarget > 0 ? Math.min((ind.annualProgress / ind.annualTarget) * 100, 100) : 0;
    return acc + (progress * (weight / 100));
  }, 0);

  const overallAverage = totalWeightSum > 0 ? Math.round((totalWeightedProgress / (totalWeightSum / 100))) : 0;

  // Offices Aggregation
  const uniqueOffices = offices.length > 0 ? offices : DOR_OFFICES_LIST;

  const filteredOffices = uniqueOffices.filter(o => 
    o.name.toLowerCase().includes(searchQuery.toLowerCase())
  );

  return (
    <AnimatePresence>
      <div className="fixed inset-0 z-[9999] overflow-hidden pointer-events-none">
        {/* Semi-transparent dark backdrop */}
        <motion.div
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          exit={{ opacity: 0 }}
          onClick={onClose}
          className="absolute inset-0 bg-slate-950/70 backdrop-blur-xs pointer-events-auto"
        />

        {/* STEP 0: Unified Modal Container */}
        {step === 0 && (
          <div className="absolute inset-0 flex items-center justify-center p-2 sm:p-4">
            <motion.div
              initial={{ scale: 0.9, opacity: 0, y: 30 }}
              animate={{ scale: 1, opacity: 1, y: 0 }}
              exit={{ scale: 0.9, opacity: 0, y: 30 }}
              transition={{ type: 'spring', damping: 25, stiffness: 210 }}
              className="relative w-full max-w-2xl bg-white dark:bg-slate-900 border border-slate-200 dark:border-white/10 rounded-[32px] shadow-2xl overflow-hidden flex flex-col max-h-[94vh] sm:max-h-[85vh] pointer-events-auto"
            >
              {/* Header with gradient accent */}
              <div className="relative px-6 py-6 border-b border-slate-100 dark:border-white/5 bg-slate-50/30 dark:bg-slate-950/20 flex justify-between items-start shrink-0">
                <div className="absolute top-0 left-0 w-32 h-32 bg-indigo-500/10 rounded-full blur-3xl -ml-16 -mt-16 pointer-events-none" />

